            <div>
              <label className="block text-sm font-medium mb-1">Location</label>
              <input required type="text" value={formData.location} onChange={e => setFormData({ ...formData, location: e.target.value })} className={`w-full px-3 py-2 rounded-lg border ${darkMode ? "bg-stone-800 border-stone-700" : "border-stone-200"}`} placeholder="Where was it found?" />
            </div>

            <div>
