function AIChatBot({ onClose, darkMode }: { onClose: () => void; darkMode: boolean }) {
  const [messages, setMessages] = useState<{ role: "user" | "model"; text: string }[]>([
    { role: "model", text: "Hello! I'm the StreetPaws assistant. How can I help you today?" }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const chatRef = useRef<any>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  useEffect(() => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      chatRef.current = ai.chats.create({
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction: "You are a helpful assistant for StreetPaws, a platform for finding homes for street animals. Help users with adoption advice, pet care tips, and using the app. Keep answers concise, friendly, and encouraging."
        }
      });
    } catch (e) {
      console.error("AI Init Error", e);
    }
  }, []);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userText = input;
    setInput("");
    setMessages((prev) => [...prev, { role: "user", text: userText }]);
    setIsLoading(true);

    try {
      if (!chatRef.current) throw new Error("Chat not initialized");
      const result = await chatRef.current.sendMessage({ message: userText });
      const responseText = result.text;
      setMessages((prev) => [...prev, { role: "model", text: responseText }]);
    } catch (error) {
      console.error("Chat Error", error);
      setMessages((prev) => [...prev, { role: "model", text: "I'm sorry, I'm having trouble connecting right now. Please try again later." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className={`fixed bottom-24 right-6 w-96 h-[500px] rounded-2xl shadow-2xl flex flex-col z-50 overflow-hidden border ${darkMode ? "bg-stone-900 border-stone-700" : "bg-white border-stone-200"}`}>
      <div className="p-4 bg-amber-500 text-white flex justify-between items-center">
        <div className="flex items-center gap-2">
          <Sparkles size={18} />
          <span className="font-bold">Paw Assistant</span>
        </div>
        <button onClick={onClose} className="hover:bg-amber-600 p-1 rounded transition-colors"><X size={18} /></button>
      </div>
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${m.role === 'user'
              ? 'bg-amber-500 text-white rounded-br-none'
              : (darkMode ? 'bg-stone-800 text-stone-200 rounded-bl-none' : 'bg-stone-100 text-stone-800 rounded-bl-none')
              }`}>
              {m.text}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className={`p-3 rounded-2xl rounded-bl-none text-sm ${darkMode ? 'bg-stone-800' : 'bg-stone-100'}`}>
              <div className="flex gap-1">
                <span className="w-2 h-2 bg-stone-400 rounded-full animate-bounce"></span>
                <span className="w-2 h-2 bg-stone-400 rounded-full animate-bounce delay-75"></span>
                <span className="w-2 h-2 bg-stone-400 rounded-full animate-bounce delay-150"></span>
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>
      <div className={`p-3 border-t ${darkMode ? "border-stone-700 bg-stone-800" : "border-stone-100 bg-stone-50"}`}>
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask about adoption..."
            className={`flex-1 px-4 py-2 rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-amber-500 ${darkMode ? "bg-stone-900 text-white" : "bg-white text-stone-800 border"}`}
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className="p-2 bg-amber-500 text-white rounded-full hover:bg-amber-600 disabled:opacity-50 transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
}

function PetFormModal({ isOpen, onClose, onSubmit, darkMode, currentUser, initialData }: {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (pet: Pet) => void;
  darkMode: boolean;
  currentUser: UserProfile | null;
  initialData?: Pet;
}) {
  const [formData, setFormData] = useState<Partial<Pet>>({
    name: "",
    type: "Dog",
    age: "",
    location: "",
    description: "",
    imageUrl: "",
    contactNumber: "",
    urgency: "Medium",
    status: "Available",
    traits: ""
  });

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    } else {
      setFormData({
        name: "",
        type: "Dog",
        age: "",
        location: "",
        description: "",
        imageUrl: "",
        contactNumber: "",
        urgency: "Medium",
        status: "Available",
        traits: ""
      });
    }
  }, [initialData, isOpen]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const coords = getRandomCoordinateNear(40.7128, -74.0060);

    const pet: Pet = {
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      name: formData.name || "Unknown",
      type: (formData.type as PetType) || "Dog",
      age: formData.age || "Unknown",
      location: formData.location || "Unknown Location",
      lat: initialData?.lat || coords.lat,
      lng: initialData?.lng || coords.lng,
      distance: initialData?.distance || Math.floor(Math.random() * 10),
      description: formData.description || "",
      imageUrl: formData.imageUrl || "https://images.unsplash.com/photo-1543466835-00a7907e9de1?auto=format&fit=crop&q=80&w=800",
      contactNumber: formData.contactNumber || "",
      postedAt: initialData?.postedAt || new Date(),
      urgency: (formData.urgency as UrgencyLevel) || "Medium",
      status: (formData.status as PetStatus) || "Available",
      traits: formData.traits || "",
      comments: initialData?.comments || [],
      cheers: initialData?.cheers || 0,
      authorId: initialData?.authorId || currentUser.id
    };
    onSubmit(pet);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in">
      <div className={`w-full max-w-lg rounded-2xl shadow-2xl max-h-[90vh] overflow-y-auto ${darkMode ? "bg-stone-900 text-white" : "bg-white text-stone-800"}`}>
