          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium mb-1">Name</label>
                <input required type="text" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} className={`w-full px-3 py-2 rounded-lg border ${darkMode ? "bg-stone-800 border-stone-700" : "border-stone-200"}`} placeholder="Pet Name" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Type</label>
                <select value={formData.type} onChange={e => setFormData({ ...formData, type: e.target.value as PetType })} className={`w-full px-3 py-2 rounded-lg border ${darkMode ? "bg-stone-800 border-stone-700" : "border-stone-200"}`}>
                  <option>Dog</option><option>Cat</option><option>Bird</option><option>Other</option>
                </select>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium mb-1">Age</label>
                <input type="text" value={formData.age} onChange={e => setFormData({ ...formData, age: e.target.value })} className={`w-full px-3 py-2 rounded-lg border ${darkMode ? "bg-stone-800 border-stone-700" : "border-stone-200"}`} placeholder="e.g. 2 years" />
              </div>
