                <select value={formData.urgency} onChange={e => setFormData({ ...formData, urgency: e.target.value as UrgencyLevel })} className={`w-full px-3 py-2 rounded-lg border ${darkMode ? "bg-stone-800 border-stone-700" : "border-stone-200"}`}>
