            </div>

            <div>
              <label className="block text-sm font-medium mb-1">Image URL</label>
              <input required type="url" value={formData.imageUrl} onChange={e => setFormData({ ...formData, imageUrl: e.target.value })} className={`w-full px-3 py-2 rounded-lg border ${darkMode ? "bg-stone-800 border-stone-700" : "border-stone-200"}`} placeholder="https://..." />
