          {/* Comments Section */}
          {showComments && (
            <div className={`mt-3 p-3 rounded-xl text-sm ${darkMode ? "bg-stone-900/50" : "bg-stone-50"}`}>
               <div className="space-y-2 mb-3 max-h-32 overflow-y-auto custom-scrollbar">
