          <div className="p-8 text-center space-y-4 flex-1">
            <div>
              <h1 className="text-5xl font-black text-stone-900 mb-2">{pet.name}</h1>
              <p className="text-xl text-stone-600 font-medium">{pet.type} • {pet.age} • {pet.location}</p>
            </div>
            <p className="text-lg leading-relaxed text-stone-700 border-y-2 border-stone-100 py-4 my-4">
              {pet.description}
            </p>
            <div className="bg-stone-900 text-white p-4 rounded-xl">
              <p className="text-sm uppercase text-stone-400 font-bold mb-1">Contact for adoption</p>
              <p className="text-2xl font-bold tracking-widest">{pet.contactNumber}</p>
            </div>
          </div>
          <div className="bg-stone-100 p-4 text-center text-stone-500 text-sm print:bg-white">
            Scan to view on StreetPaws • Listed on {pet.postedAt.toLocaleDateString()}
          </div>
        </div>

        <div className="p-4 bg-stone-100 border-t print:hidden flex gap-2">
          <button onClick={() => window.print()} className="flex-1 bg-stone-900 text-white font-bold py-3 rounded-xl flex items-center justify-center gap-2 hover:bg-black transition-colors">
            <Printer size={18} /> Print Poster
          </button>
        </div>
      </div>
    </div>
  );
}

function AuthModal({ onClose, onLogin, darkMode }: { onClose: () => void; onLogin: (user: UserProfile) => void; darkMode: boolean }) {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (name && email) {
      onLogin({
        id: Math.random().toString(36),
        name,
        email,
        joinedAt: new Date()
      });
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in">
      <div className={`w-full max-w-sm rounded-2xl shadow-2xl p-8 ${darkMode ? "bg-stone-900 text-white" : "bg-white text-stone-800"}`}>
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-amber-500 rounded-full flex items-center justify-center mx-auto mb-4 text-white shadow-lg shadow-amber-500/30">
            <PawPrint size={32} />
          </div>
          <h2 className="text-2xl font-bold">Welcome to StreetPaws</h2>
          <p className={`text-sm mt-2 ${darkMode ? "text-stone-400" : "text-stone-500"}`}>Join the community to help street animals.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-xs font-bold uppercase mb-1 opacity-70">Name</label>
            <input required value={name} onChange={e => setName(e.target.value)} type="text" className={`w-full px-4 py-3 rounded-xl border focus:ring-2 focus:ring-amber-500 outline-none transition-all ${darkMode ? "bg-stone-800 border-stone-700" : "bg-stone-50 border-stone-200"}`} placeholder="Your Name" />
          </div>
          <div>
            <label className="block text-xs font-bold uppercase mb-1 opacity-70">Email</label>
            <input required value={email} onChange={e => setEmail(e.target.value)} type="email" className={`w-full px-4 py-3 rounded-xl border focus:ring-2 focus:ring-amber-500 outline-none transition-all ${darkMode ? "bg-stone-800 border-stone-700" : "bg-stone-50 border-stone-200"}`} placeholder="you@example.com" />
          </div>
          <button type="submit" className="w-full bg-amber-500 hover:bg-amber-600 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg hover:shadow-amber-500/25 mt-4">
            Start Exploring
          </button>
        </form>
        <button onClick={onClose} className="w-full mt-4 text-sm font-medium opacity-50 hover:opacity-100 transition-opacity">
          Cancel
        </button>
      </div>
    </div>
  );
}

// --- Main Component ---

function App() {
  const [pets, setPets] = useState<Pet[]>(INITIAL_PETS);
  const [currentView, setCurrentView] = useState<AppView>("feed");

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPet, setEditingPet] = useState<Pet | null>(null);

  const [isAuthOpen, setIsAuthOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);

  // Filter/Sort States
  const [selectedType, setSelectedType] = useState<FilterType>("All");
  const [searchTerm, setSearchTerm] = useState("");
  const [sortBy, setSortBy] = useState<SortOption>("Newest");
  const [viewMode, setViewMode] = useState<ViewMode>("grid");

  // UI States
  const [darkMode, setDarkMode] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [posterPet, setPosterPet] = useState<Pet | null>(null);
  const [toasts, setToasts] = useState<Toast[]>([]);
  const [viewingPet, setViewingPet] = useState<Pet | null>(null);

  // Theme & Auth Init
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add("dark");
    } else {
      document.documentElement.classList.remove("dark");
    }
  }, [darkMode]);

  useEffect(() => {
    const savedUser = localStorage.getItem("streetpaws_user");
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = (user: UserProfile) => {
    setCurrentUser(user);
    localStorage.setItem("streetpaws_user", JSON.stringify(user));
    setIsAuthOpen(false);
    addToast(`Welcome back, ${user.name}!`, "success");
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem("streetpaws_user");
    setCurrentView("feed");
    addToast("Logged out successfully.", "info");
  };

  // Favorites
  const [favorites, setFavorites] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem("streetpaws_favorites");
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const addToast = (message: string, type: Toast["type"] = "info") => {
    const id = Math.random().toString(36);
    setToasts((prev) => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts((prev) => prev.filter((t) => t.id !== id));
    }, 3000);
  };

  const toggleFavorite = (petId: string) => {
    setFavorites((prev) => {
      const newFavs = prev.includes(petId) ? prev.filter(id => id !== petId) : [...prev, petId];
      localStorage.setItem("streetpaws_favorites", JSON.stringify(newFavs));
      return newFavs;
    });
    addToast(favorites.includes(petId) ? "Removed from favorites" : "Added to favorites", "success");
  };

  const updatePet = (petId: string, updates: Partial<Pet>) => {
    setPets(pets.map(p => p.id === petId ? { ...p, ...updates } : p));
  };

  const handleAddComment = (petId: string, text: string) => {
    if (!currentUser) {
       setIsAuthOpen(true);
       return;
    }
    const newComment: Comment = {
      id: Math.random().toString(36),
      text,
      author: currentUser.name,
      createdAt: new Date(),
    };
    updatePet(petId, { comments: [...pets.find(p => p.id === petId)!.comments, newComment] });
    addToast("Note added!", "success");
  };

  const handleCheer = (petId: string) => {
    const pet = pets.find(p => p.id === petId);
    if (pet) updatePet(petId, { cheers: pet.cheers + 1 });
  };

  const handleStatusChange = (petId: string, status: PetStatus) => {
     updatePet(petId, { status });
     addToast(`Status updated to ${status}`, "success");
  }

  // Filtering & Sorting
  const filteredPets = pets.filter((pet) => {
    const matchesType =
      selectedType === "All" ? true :
      selectedType === "Favorites" ? favorites.includes(pet.id) :
      selectedType === "Urgent" ? (pet.urgency === "High" || pet.urgency === "Critical") :
      pet.type === selectedType;

    const matchesSearch =
      pet.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      pet.location.toLowerCase().includes(searchTerm.toLowerCase());

    return matchesType && matchesSearch;
  });

  const sortedAndFilteredPets = [...filteredPets].sort((a, b) => {
    if (a.status === "Adopted" && b.status !== "Adopted") return 1;
    if (b.status === "Adopted" && a.status !== "Adopted") return -1;

    if (sortBy === "Newest") return b.postedAt.getTime() - a.postedAt.getTime();
    if (sortBy === "Oldest") return a.postedAt.getTime() - b.postedAt.getTime();
    if (sortBy === "Name") return a.name.localeCompare(b.name);
    if (sortBy === "Age") return getAgeInMonths(a.age) - getAgeInMonths(b.age);
    if (sortBy === "Urgency") return urgencyScore(b.urgency) - urgencyScore(a.urgency);
    return 0;
  });

  // Modal Handlers
  const openListStrayModal = () => {
    if (!currentUser) {
      setIsAuthOpen(true);
      addToast("Please login to list a stray.", "info");
    } else {
      setEditingPet(null);
      setIsModalOpen(true);
    }
  };

  const openEditPetModal = (pet: Pet) => {
    setEditingPet(pet);
    setIsModalOpen(true);
  };

  const handleDeletePet = (petId: string) => {
    if (window.confirm("Are you sure you want to delete this listing? This cannot be undone.")) {
      setPets(prev => prev.filter(p => p.id !== petId));
      addToast("Listing deleted successfully.", "success");
    }
  };

  const handleSavePet = (petData: Pet) => {
    if (editingPet) {
      // Update existing
      setPets(prev => prev.map(p => p.id === petData.id ? petData : p));
      addToast("Pet details updated!", "success");
    } else {
      // Create new
      setPets(prev => [petData, ...prev]);
      addToast("Pet listed successfully!", "success");
    }
    setIsModalOpen(false);
    setEditingPet(null);
  };

  return (
    <div className={`min-h-screen font-sans transition-colors duration-300 ${darkMode ? "bg-stone-900 text-stone-100" : "bg-stone-50 text-stone-800"}`}>

      {/* Toast Container */}
      <div className="fixed top-4 right-4 z-50 space-y-2 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className={`pointer-events-auto px-4 py-3 rounded-xl shadow-lg flex items-center gap-2 animate-in slide-in-from-right-10 ${
            toast.type === "success" ? "bg-green-500 text-white" : "bg-stone-800 text-white"
          }`}>
            {toast.type === "success" && <CheckCircle2 size={16} />}
            <span className="text-sm font-medium">{toast.message}</span>
          </div>
        ))}
      </div>

      {/* Header */}
      <header className={`relative z-40 border-b shadow-sm transition-colors ${darkMode ? "bg-stone-900 border-stone-800" : "bg-white border-stone-200"}`}>
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <button 
            onClick={() => setCurrentView("feed")}
            className="flex items-center gap-2 hover:opacity-80 transition-opacity"
          >
            <div className="w-10 h-10 bg-amber-500 rounded-full flex items-center justify-center text-white shadow-sm">
              <PawPrint size={22} />
            </div>
            <h1 className={`text-xl font-bold tracking-tight ${darkMode ? "text-stone-100" : "text-stone-800"}`}>
              Street<span className="text-amber-500">Paws</span>
            </h1>
          </button>

          <div className="flex items-center gap-3">
             <button
              onClick={() => setDarkMode(!darkMode)}
              className={`p-2 rounded-full transition-colors ${darkMode ? "bg-stone-800 text-amber-400 hover:bg-stone-700" : "bg-stone-100 text-stone-600 hover:bg-stone-200"}`}
            >
              {darkMode ? <Sun size={18} /> : <Moon size={18} />}
            </button>

            {currentUser ? (
              <div className="flex items-center gap-2 pl-2 border-l border-stone-200 ml-2">
                <button 
                  onClick={() => setCurrentView("profile")}
                  className={`flex items-center gap-2 px-2 py-1 rounded-full transition-all ${
                    currentView === 'profile' 
                      ? (darkMode ? "bg-stone-800" : "bg-stone-100") 
                      : "hover:bg-stone-100 dark:hover:bg-stone-800"
                  }`}
                >
                  <div className="hidden sm:flex flex-col items-end">
                    <span className="text-xs font-bold leading-tight max-w-[80px] truncate">{currentUser.name}</span>
                  </div>
                  <div className="w-9 h-9 bg-amber-200 rounded-full flex items-center justify-center text-amber-700 font-bold border-2 border-white shadow-sm">
                    {currentUser.name.charAt(0)}
                  </div>
                </button>
              </div>
            ) : (
              <button
                onClick={() => setIsAuthOpen(true)}
                className={`text-sm font-bold px-4 py-2 rounded-full transition-colors ${darkMode ? "text-stone-300 hover:text-white" : "text-stone-600 hover:text-stone-900"}`}
              >
                Login
              </button>
            )}

            <button
              onClick={openListStrayModal}
              className="bg-amber-600 text-white px-4 py-2 rounded-full font-medium text-sm hover:bg-amber-700 transition-all flex items-center gap-2 shadow-md hover:shadow-lg active:scale-95"
            >
              <Plus size={18} />
              <span className="hidden sm:inline">List Stray</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      {currentView === "feed" ? (
        <>
          {/* Hero */}
          <div className={`py-12 px-4 border-b transition-colors ${darkMode ? "bg-stone-800 border-stone-700" : "bg-amber-100/50 border-amber-100"}`}>
            <div className="max-w-3xl mx-auto text-center space-y-4">
              <h2 className={`text-3xl md:text-5xl font-extrabold tracking-tight leading-tight ${darkMode ? "text-white" : "text-stone-800"}`}>
                Every street friend deserves a <span className="text-amber-500">home</span>.
              </h2>
              <p className={`text-lg max-w-2xl mx-auto ${darkMode ? "text-stone-300" : "text-stone-600"}`}>
                Connect with your community to adopt, foster, and care for local animals.
              </p>
            </div>
          </div>

          <main className="max-w-7xl mx-auto px-4 py-8">
            {/* Toolbar */}
            <div className="flex flex-col lg:flex-row gap-4 mb-8 justify-between items-center sticky top-2 z-30 py-3 bg-opacity-95 backdrop-blur-md rounded-xl transition-all">

              <div className="flex gap-2 overflow-x-auto pb-2 w-full lg:w-auto no-scrollbar mask-gradient">
                {["All", "Favorites", "Urgent", "Dog", "Cat", "Bird", "Other"].map((type) => (
                  <button
                    key={type}
                    onClick={() => setSelectedType(type as FilterType)}
                    className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors border flex items-center gap-2 ${
                      selectedType === type
                        ? "bg-amber-500 text-white border-amber-500"
                        : darkMode 
                          ? "bg-stone-800 border-stone-700 text-stone-300 hover:bg-stone-700"
                          : "bg-white border-stone-200 text-stone-600 hover:bg-stone-50"
                    }`}
                  >
                    {type === "Favorites" && <Heart size={14} className={selectedType === "Favorites" ? "fill-white" : ""} />}
                    {type === "Urgent" && <Siren size={14} />}
                    {type}
                  </button>
                ))}
              </div>

              <div className="flex flex-col sm:flex-row gap-3 w-full lg:w-auto items-center">
                {/* View Toggle */}
                <div className={`flex items-center p-1 rounded-lg border ${darkMode ? "bg-stone-800 border-stone-700" : "bg-white border-stone-200"}`}>
                    <button 
                      onClick={() => setViewMode("grid")}
                      className={`p-2 rounded-md transition-all ${viewMode === "grid" ? (darkMode ? "bg-stone-700 text-white" : "bg-stone-100 text-stone-900") : "text-stone-400"}`}
                      title="Grid View"
                    >
                      <Grid size={18} />
                    </button>
                    <button 
                      onClick={() => setViewMode("list")}
                      className={`p-2 rounded-md transition-all ${viewMode === "list" ? (darkMode ? "bg-stone-700 text-white" : "bg-stone-100 text-stone-900") : "text-stone-400"}`}
                      title="List View"
                    >
                      <List size={18} />
                    </button>
                    <button 
                      onClick={() => setViewMode("map")}
                      className={`p-2 rounded-md transition-all ${viewMode === "map" ? (darkMode ? "bg-stone-700 text-white" : "bg-stone-100 text-stone-900") : "text-stone-400"}`}
                      title="Map View"
                    >
                      <MapIcon size={18} />
                    </button>
                </div>

                {/* Search */}
                <div className="relative flex-1 sm:w-64 w-full">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
                  <input
                    type="text"
                    placeholder="Search location or name..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className={`w-full pl-10 pr-4 py-2.5 rounded-full border focus:outline-none focus:ring-2 focus:ring-amber-500/50 transition-all text-sm ${
                      darkMode ? "bg-stone-800 border-stone-700 text-white placeholder-stone-500" : "bg-white border-stone-200 text-stone-800 placeholder-stone-400"
                    }`}
                  />
                </div>

                {/* Sort */}
                <div className="relative shrink-0 w-full sm:w-auto">
                  <select
                    value={sortBy}
                    onChange={(e) => setSortBy(e.target.value as SortOption)}
                    className={`w-full sm:w-auto pl-4 pr-10 py-2.5 rounded-full border focus:outline-none focus:ring-2 focus:ring-amber-500/50 transition-all text-sm font-medium appearance-none cursor-pointer ${
                      darkMode ? "bg-stone-800 border-stone-700 text-white" : "bg-white border-stone-200 text-stone-600"
                    }`}
                  >
                    <option value="Newest">Newest</option>
                    <option value="Oldest">Oldest</option>
                    <option value="Urgency">Urgency</option>
                    <option value="Age">Youngest</option>
                    <option value="Name">Name</option>
                  </select>
                  <ArrowUpDown className="absolute right-3 top-1/2 -translate-y-1/2 text-stone-400 pointer-events-none" size={14} />
                </div>
              </div>
            </div>

            {/* Feed */}
            {viewMode === 'map' ? (
              <MapView pets={sortedAndFilteredPets} darkMode={darkMode} onSelectPet={setViewingPet} />
            ) : (
              <div className={`grid gap-6 ${viewMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1'}`}>
                {sortedAndFilteredPets.map((pet) => (
                  <PetCard
                    key={pet.id}
                    pet={pet}
                    darkMode={darkMode}
                    viewMode={viewMode}
                    currentUser={currentUser}
                    isFavorite={favorites.includes(pet.id)}
                    onToggleFavorite={() => toggleFavorite(pet.id)}
                    onGeneratePoster={() => setPosterPet(pet)}
                    onAddComment={handleAddComment}
                    onCheer={handleCheer}
                    onStatusChange={handleStatusChange}
                    onReport={() => addToast("Listing reported to moderation team.", "info")}
                    isOwner={false} // In feed view, regular behavior
                    onToast={addToast}
                  />
                ))}
              </div>
            )}

            {sortedAndFilteredPets.length === 0 && (
                <div className={`py-20 text-center rounded-3xl border border-dashed ${darkMode ? "border-stone-700 text-stone-500" : "border-stone-200 text-stone-400"}`}>
                  <p className="text-xl font-medium">No pets found matching your criteria.</p>
                </div>
            )}
          </main>
        </>
      ) : (
        /* Profile View */
        <ProfileView 
           currentUser={currentUser!} 
           pets={pets} 
           darkMode={darkMode}
           onEdit={openEditPetModal}
           onDelete={handleDeletePet}
           onBack={() => setCurrentView("feed")}
           onLogout={handleLogout}
           onToggleFavorite={toggleFavorite}
           favorites={favorites}
           setPosterPet={setPosterPet}
           handleAddComment={handleAddComment}
           handleCheer={handleCheer}
           handleStatusChange={handleStatusChange}
           onToast={addToast}
        />
      )}

      {/* Floating Chat Bot */}
      <div className="fixed bottom-6 right-6 z-40">
        <button
          onClick={() => setIsChatOpen(!isChatOpen)}
          className="bg-amber-600 hover:bg-amber-500 text-white p-4 rounded-full shadow-xl hover:scale-105 transition-all flex items-center justify-center"
        >
          {isChatOpen ? <X size={24} /> : <Stethoscope size={24} />}
        </button>
      </div>

      {isChatOpen && (
        <AIChatBot onClose={() => setIsChatOpen(false)} darkMode={darkMode} />
      )}

      {/* Modals */}
      {isModalOpen && (
        <PetFormModal
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          onSubmit={handleSavePet}
          darkMode={darkMode}
          currentUser={currentUser}
          initialData={editingPet || undefined}
        />
      )}

      {posterPet && (
        <PosterModal 
          pet={posterPet} 
          onClose={() => setPosterPet(null)} 
        />
      )}

      {/* Viewing Pet Details Modal (From Map or other interactions) */}
      {viewingPet && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in"
          onClick={() => setViewingPet(null)}
        >
          <div className="relative w-full max-w-sm" onClick={(e) => e.stopPropagation()}>
            <button 
              onClick={() => setViewingPet(null)}
              className="absolute -top-12 right-0 p-2 bg-white/10 text-white rounded-full hover:bg-white/20 transition-colors"
            >
              <X size={24} />
            </button>
            <PetCard
              pet={viewingPet}
              darkMode={darkMode}
              viewMode="grid"
              currentUser={currentUser}
              isFavorite={favorites.includes(viewingPet.id)}
              onToggleFavorite={() => toggleFavorite(viewingPet.id)}
              onGeneratePoster={() => setPosterPet(viewingPet)}
              onAddComment={handleAddComment}
              onCheer={handleCheer}
              onStatusChange={handleStatusChange}
              onReport={() => addToast("Listing reported to moderation team.", "info")}
              isOwner={currentUser?.id === viewingPet.authorId}
              onEdit={() => {
                setViewingPet(null);
                openEditPetModal(viewingPet);
              }}
              onDelete={() => {
                setViewingPet(null);
                handleDeletePet(viewingPet.id);
              }}
              onToast={addToast}
            />
          </div>
        </div>
      )}

      {isAuthOpen && (
        <AuthModal 
          onClose={() => setIsAuthOpen(false)} 
          onLogin={handleLogin}
          darkMode={darkMode}
        />
      )}
    </div>
  );
}

// --- Map View Component ---

const MapView: React.FC<{ pets: Pet[], darkMode: boolean, onSelectPet: (pet: Pet) => void }> = ({ pets, darkMode, onSelectPet }) => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<L.Map | null>(null);

  useEffect(() => {
    if (!mapContainer.current) return;
    if (mapInstance.current) return; // Initialize only once

    // Default center (NYC-ish)
    const map = L.map(mapContainer.current).setView([40.7128, -74.0060], 13);

    // Add Tiles
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
      className: darkMode ? 'map-tiles-dark' : '' 
    }).addTo(map);

    mapInstance.current = map;

    // Fix: Invalidate size to ensure map renders correctly if container size calculation was delayed
    setTimeout(() => {
      map.invalidateSize();
    }, 100);
  }, []);

  // Update markers when pets change
  useEffect(() => {
    if (!mapInstance.current) return;
    const map = mapInstance.current;

    // Clear existing layers (except tiles)
    map.eachLayer((layer) => {
       if (layer instanceof L.CircleMarker || layer instanceof L.Marker) {
         map.removeLayer(layer);
       }
    });

    const markers = L.featureGroup();

    pets.forEach(pet => {
       if (pet.lat && pet.lng) {
          const color = 
            pet.urgency === 'Critical' ? '#ef4444' : 
            pet.urgency === 'High' ? '#f97316' : 
            pet.urgency === 'Medium' ? '#fbbf24' : '#22c55e';

          const marker = L.circleMarker([pet.lat, pet.lng], {
            radius: 10,
            fillColor: color,
            color: '#fff',
            weight: 2,
            opacity: 1,
            fillOpacity: 0.8
          }).addTo(map);

          // Create DOM element for popup content
          const container = document.createElement('div');
          container.style.minWidth = "200px";
          container.style.fontFamily = "sans-serif";

          // Image Container
          const imgContainer = document.createElement('div');
          imgContainer.style.height = "120px";
          imgContainer.style.width = "100%";
          imgContainer.style.overflow = "hidden";
          imgContainer.style.borderRadius = "8px 8px 0 0";
          imgContainer.style.marginBottom = "8px";

          const img = document.createElement('img');
          img.src = pet.imageUrl;
          img.style.width = "100%";
          img.style.height = "100%";
          img.style.objectFit = "cover";
          imgContainer.appendChild(img);

          // Title
          const title = document.createElement('h3');
          title.textContent = pet.name;
          title.style.margin = "0";
          title.style.fontWeight = "bold";
          title.style.fontSize = "16px";
          title.style.color = "#333";

          // Info
          const subInfo = document.createElement('p');
          subInfo.textContent = `${pet.type} • ${pet.age}`;
          subInfo.style.margin = "4px 0";
          subInfo.style.fontSize = "12px";
          subInfo.style.color = "#666";

          const locInfo = document.createElement('p');
          locInfo.textContent = pet.location;
          locInfo.style.margin = "4px 0";
          locInfo.style.fontSize = "12px";
          locInfo.style.color = "#666";

          // View Details Button
          const btn = document.createElement('button');
          btn.textContent = "View Details";
          btn.style.width = "100%";
          btn.style.marginTop = "8px";
          btn.style.backgroundColor = "#f59e0b"; // Amber-500
          btn.style.color = "white";
          btn.style.padding = "8px";
          btn.style.borderRadius = "6px";
          btn.style.fontWeight = "bold";
          btn.style.fontSize = "12px";
          btn.style.border = "none";
          btn.style.cursor = "pointer";
          btn.onclick = () => onSelectPet(pet); // Trigger React callback

          container.appendChild(imgContainer);
          container.appendChild(title);
          container.appendChild(subInfo);
          container.appendChild(locInfo);
          container.appendChild(btn);

          marker.bindPopup(container);
          markers.addLayer(marker);
       }
    });

    if (pets.length > 0 && markers.getLayers().length > 0) {
      map.fitBounds(markers.getBounds(), { padding: [50, 50] });
    }

  }, [pets, darkMode, onSelectPet]);

  return (
     <div className={`w-full h-[600px] rounded-2xl overflow-hidden shadow-inner border relative z-0 ${darkMode ? "border-stone-700" : "border-stone-200"}`}>
        <div ref={mapContainer} className="w-full h-full" id="map" />
        {/* CSS filter to dark mode the map tiles if needed */}
        {darkMode && (
          <style>{`
            .leaflet-layer { filter: invert(100%) hue-rotate(180deg) brightness(95%) contrast(90%); }
          `}</style>
        )}
     </div>
  );
};


