// --- Auth Modal (Restored & Upgraded) ---
function AuthModal({ isOpen, onClose, onLogin, darkMode }: { isOpen: boolean; onClose: () => void; onLogin: (user: any) => void; darkMode: boolean }) {
    const [mode, setMode] = useState<'login' | 'signup'>('login');
    const [name, setName] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        // Simulating Firebase Authentication flow
        // In a real implementation with Firebase keys, you would use:
        // createUserWithEmailAndPassword(auth, email, password) or signInWithEmailAndPassword(auth, email, password)

        try {
             // Use existing mock backend to simulate persistence or valid auth check
            if (mode === 'signup') {
                // Mock Signup
                 const mockUser = {
                    id: Math.random().toString(36),
                    name,
                    email,
                    joinedAt: new Date().toISOString(),
                    token: "mock-firebase-token-" + Date.now()
                };
                // Simulate network delay
                await new Promise(resolve => setTimeout(resolve, 1000));
                onLogin(mockUser);
            } else {
                 // Mock Login
                 const mockUser = {
                    id: "u_existing_" + Math.random().toString(36).substr(2,5),
                    name: "Demo User",
                    email: email,
                    joinedAt: new Date().toISOString(),
                    token: "mock-firebase-token-" + Date.now()
                };
                await new Promise(resolve => setTimeout(resolve, 1000));
                onLogin(mockUser);
            }
        } catch (err) {
            setError("Authentication failed. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    const inputClass = `w-full px-4 py-3 rounded-xl border focus:ring-2 focus:ring-amber-500 outline-none transition-all ${darkMode ? "bg-stone-800 border-stone-700 text-white" : "bg-stone-50 border-stone-200"}`;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in">
            <div className={`w-full max-w-sm rounded-2xl shadow-2xl p-8 ${darkMode ? "bg-stone-900 text-white" : "bg-white text-stone-800"}`}>
                <div className="text-center mb-6">
                    <div className="w-16 h-16 bg-amber-500 rounded-full flex items-center justify-center mx-auto mb-4 text-white shadow-lg shadow-amber-500/30">
                        <PawPrint size={32} />
                    </div>
                    <h2 className="text-2xl font-bold">Welcome to StreetPaws</h2>
                    <p className={`text-sm mt-2 ${darkMode ? "text-stone-400" : "text-stone-500"}`}>Join the community to help street animals.</p>
                </div>

                <div className="flex mb-6 border-b border-stone-200 dark:border-stone-700">
                    <button 
                        onClick={() => setMode('login')} 
                        className={`flex-1 pb-2 text-sm font-bold border-b-2 transition-colors ${mode === 'login' ? 'border-amber-500 text-amber-500' : 'border-transparent text-stone-400 hover:text-stone-600'}`}
                    >
                        Login
                    </button>
                    <button 
                        onClick={() => setMode('signup')} 
                        className={`flex-1 pb-2 text-sm font-bold border-b-2 transition-colors ${mode === 'signup' ? 'border-amber-500 text-amber-500' : 'border-transparent text-stone-400 hover:text-stone-600'}`}
                    >
                        Sign Up
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {mode === 'signup' && (
                        <div>
                            <label className="block text-xs font-bold uppercase mb-1 opacity-70">Name</label>
                            <input required value={name} onChange={e => setName(e.target.value)} type="text" className={inputClass} placeholder="Your Name" />
                        </div>
                    )}
                    <div>
                        <label className="block text-xs font-bold uppercase mb-1 opacity-70">Email</label>
                        <input required value={email} onChange={e => setEmail(e.target.value)} type="email" className={inputClass} placeholder="you@example.com" />
                    </div>
                    <div>
                        <label className="block text-xs font-bold uppercase mb-1 opacity-70">Password</label>
                        <input required value={password} onChange={e => setPassword(e.target.value)} type="password" className={inputClass} placeholder="••••••••" />
                    </div>

                    {error && <div className="text-red-500 text-sm text-center">{error}</div>}

                    <button disabled={loading} type="submit" className="w-full bg-amber-500 hover:bg-amber-600 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg hover:shadow-amber-500/25 mt-4 disabled:opacity-50">
                        {loading ? 'Processing...' : (mode === 'login' ? 'Login' : 'Create Account')}
                    </button>
                </form>
                <button onClick={onClose} className="w-full mt-4 text-sm font-medium opacity-50 hover:opacity-100 transition-opacity">
                    Cancel
                </button>
            </div>
        </div>
    );
}

// --- Recommendation Modal Component ---
function RecommendationModal({ isOpen, onClose, pets, onRecommend, darkMode }: { isOpen: boolean, onClose: () => void, pets: Pet[], onRecommend: (ids: string[]) => void, darkMode: boolean }) {
    const [step, setStep] = useState(1);
    const [answers, setAnswers] = useState({
        type: 'Any',
        energy: 'Moderate',
        space: 'Small'
    });

    if (!isOpen) return null;

    const handleNext = () => setStep(step + 1);

    const handleFinish = () => {
        // Simple matching logic
        const matches = pets.filter(pet => {
            let score = 0;
            // Type Match
            if (answers.type === 'Any' || pet.type === answers.type) score += 2;

            // Energy Match (using basic keyword matching in traits/description)
            const text = (pet.traits + ' ' + pet.description).toLowerCase();
            if (answers.energy === 'Active' && (text.includes('playful') || text.includes('energetic') || text.includes('young'))) score += 1;
            if (answers.energy === 'Chill' && (text.includes('calm') || text.includes('senior') || text.includes('gentle') || text.includes('lazy'))) score += 1;

            // Space Match
            if (answers.space === 'Large' && pet.type === 'Dog') score += 1; // Dogs bonus for large space
            if (answers.space === 'Small' && (pet.type === 'Cat' || pet.type === 'Bird' || pet.type === 'Rat' || text.includes('small'))) score += 1;

            return score >= 2;
        });

        onRecommend(matches.map(p => p.id));
    };

    const cardClass = `p-6 rounded-2xl shadow-2xl w-full max-w-md ${darkMode ? "bg-stone-900 text-white" : "bg-white text-stone-800"}`;
    const btnClass = `w-full py-4 rounded-xl border-2 font-bold text-lg transition-all flex items-center justify-center gap-3 ${darkMode ? "border-stone-700 hover:bg-stone-800" : "border-stone-200 hover:bg-amber-50 hover:border-amber-200"}`;
    const activeBtnClass = `border-amber-500 bg-amber-500 text-white shadow-lg`;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in">
            <div className={cardClass}>
                <div className="flex justify-between items-center mb-6">
                    <div className="flex items-center gap-2">
                         <Sparkles className="text-amber-500" />
                         <h2 className="text-xl font-bold">Find My Match</h2>
                    </div>
                    <button onClick={onClose}><X size={24} className="opacity-50 hover:opacity-100" /></button>
                </div>

                {/* Progress Bar */}
                <div className="w-full h-2 bg-stone-200 dark:bg-stone-800 rounded-full mb-8 overflow-hidden">
                    <div className="h-full bg-amber-500 transition-all duration-300" style={{ width: `${(step / 3) * 100}%` }}></div>
                </div>

                {step === 1 && (
                    <div className="space-y-4 animate-in slide-in-from-right">
                        <h3 className="text-2xl font-bold text-center mb-6">What kind of friend are you looking for?</h3>
                        <div className="grid grid-cols-2 gap-3">
                            {['Dog', 'Cat', 'Bird', 'Any'].map(t => (
                                <button 
                                    key={t}
                                    onClick={() => setAnswers({...answers, type: t})}
                                    className={`${btnClass} ${answers.type === t ? activeBtnClass : ''}`}
                                >
                                    {t === 'Dog' && <Dog />}
                                    {t === 'Cat' && <Cat />}
                                    {t === 'Bird' && <Bird />}
                                    {t === 'Any' && <Heart />}
                                    {t}
                                </button>
                            ))}
                        </div>
                        <button onClick={handleNext} className="w-full bg-stone-900 text-white py-3 rounded-xl font-bold mt-4">Next</button>
                    </div>
                )}

                {step === 2 && (
                    <div className="space-y-4 animate-in slide-in-from-right">
                        <h3 className="text-2xl font-bold text-center mb-6">What is your energy level?</h3>
                        <div className="space-y-3">
                            <button onClick={() => setAnswers({...answers, energy: 'Chill'})} className={`${btnClass} ${answers.energy === 'Chill' ? activeBtnClass : ''}`}>
                                <Coffee /> Chill & Relaxed
                            </button>
                             <button onClick={() => setAnswers({...answers, energy: 'Moderate'})} className={`${btnClass} ${answers.energy === 'Moderate' ? activeBtnClass : ''}`}>
                                <Zap className="opacity-50" /> Moderate
                            </button>
                            <button onClick={() => setAnswers({...answers, energy: 'Active'})} className={`${btnClass} ${answers.energy === 'Active' ? activeBtnClass : ''}`}>
                                <Zap /> Active & Playful
                            </button>
                        </div>
                        <div className="flex gap-2 mt-4">
                             <button onClick={() => setStep(1)} className="flex-1 border py-3 rounded-xl font-bold opacity-70">Back</button>
                             <button onClick={handleNext} className="flex-[2] bg-stone-900 text-white py-3 rounded-xl font-bold">Next</button>
                        </div>
                    </div>
                )}

                {step === 3 && (
                    <div className="space-y-4 animate-in slide-in-from-right">
                        <h3 className="text-2xl font-bold text-center mb-6">Describe your living space</h3>
                        <div className="grid grid-cols-2 gap-3">
                            <button onClick={() => setAnswers({...answers, space: 'Small'})} className={`${btnClass} ${answers.space === 'Small' ? activeBtnClass : ''}`}>
                                <Home size={20} /> Small / Apartment
                            </button>
                            <button onClick={() => setAnswers({...answers, space: 'Large'})} className={`${btnClass} ${answers.space === 'Large' ? activeBtnClass : ''}`}>
                                <Ruler size={20} /> Large / Yard
                            </button>
                        </div>
                         <div className="flex gap-2 mt-4">
                             <button onClick={() => setStep(2)} className="flex-1 border py-3 rounded-xl font-bold opacity-70">Back</button>
                             <button onClick={handleFinish} className="flex-[2] bg-gradient-to-r from-amber-500 to-orange-600 text-white py-3 rounded-xl font-bold shadow-lg">Show Matches</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

// --- Profile View Component ---
const ProfileView: React.FC<{
  currentUser: UserProfile;
  pets: Pet[];
  darkMode: boolean;
  onEdit: (pet: Pet) => void;
  onDelete: (id: string) => void;
  onBack: () => void;
  onLogout: () => void;
  onToggleFavorite: (id: string) => void;
  favorites: string[];
  setPosterPet: (pet: Pet) => void;
  handleAddComment: (id: string, text: string) => void;
  handleCheer: (id: string) => void;
  handleStatusChange: (id: string, status: PetStatus) => void;
  onUpdateProfile?: (updates: { name?: string; email?: string; password?: string }) => Promise<any> | null;
}> = ({ currentUser, pets, darkMode, onEdit, onDelete, onBack, onLogout, onToggleFavorite, favorites, setPosterPet, handleAddComment, handleCheer, handleStatusChange, onUpdateProfile }) => {

  const myPets = pets.filter(p => p.authorId === currentUser.id);
  const totalCheers = myPets.reduce((acc, curr) => acc + curr.cheers, 0);
  // profile edit states
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState(currentUser.name || '');
  const [editEmail, setEditEmail] = useState(currentUser.email || '');
  const [editLoading, setEditLoading] = useState(false);
  const [editError, setEditError] = useState<string | null>(null);
  const [profileImageData, setProfileImageData] = useState<string | null>(null);
  const [profileImageType, setProfileImageType] = useState<string | null>(null);
  const [profileImageUrl, setProfileImageUrl] = useState<string | null>(null);

  useEffect(() => {
    setEditName(currentUser.name || '');
    setEditEmail(currentUser.email || '');
    // initialize profile image preview from saved avatar
    setProfileImageUrl(currentUser.avatar || null);
    setProfileImageData(null);
    setProfileImageType(null);
  }, [currentUser]);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 animate-in fade-in slide-in-from-bottom-4">
      <button 
        onClick={onBack}
        className={`mb-6 flex items-center gap-2 text-sm font-medium ${darkMode ? "text-stone-400 hover:text-white" : "text-stone-500 hover:text-stone-800"}`}
      >
        <Home size={16} /> Back to Feed
      </button>

      {/* Profile Header Card */}
      <div className={`rounded-3xl p-8 mb-10 border shadow-sm ${darkMode ? "bg-stone-800 border-stone-700" : "bg-white border-stone-200"}`}>
        <div className="flex flex-col md:flex-row items-center gap-8">
           <div className="relative">
             <div className="w-32 h-32 rounded-full overflow-hidden border-4 border-white dark:border-stone-600 shadow-lg bg-amber-200 flex items-center justify-center">
               {currentUser.avatar ? (
                 <img src={currentUser.avatar} alt={currentUser.name} className="w-full h-full object-cover" />
               ) : (
                 <div className="w-full h-full flex items-center justify-center text-5xl font-bold text-amber-700">{currentUser.name.charAt(0)}</div>
               )}
             </div>
             <div className="absolute bottom-0 right-0 bg-green-500 p-2 rounded-full border-4 border-white dark:border-stone-800">
               <CheckCircle2 size={20} className="text-white" />
             </div>
           </div>

            <div className="flex-1 text-center md:text-left space-y-2">
              <div className="flex items-center justify-center md:justify-start gap-2">
                {!isEditing ? (
                  <>
                    <h2 className={`text-3xl font-bold ${darkMode ? "text-white" : "text-stone-800"}`}>{currentUser.name}</h2>
                    <button title="Edit profile" onClick={() => { setIsEditing(true); setEditError(null); }} className="p-1 rounded-md hover:bg-stone-100 dark:hover:bg-stone-700">
                      <Pencil size={18} className="text-stone-400" />
                    </button>
                  </>
                ) : (
                  <div className="flex flex-col gap-2 w-full max-w-sm">
                    <input className="px-3 py-2 rounded-md border" value={editName} onChange={(e) => setEditName(e.target.value)} />
                    <input className="px-3 py-2 rounded-md border" value={editEmail} onChange={(e) => setEditEmail(e.target.value)} />
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-medium text-stone-500">Profile Photo (optional)</label>
                      <div className="flex items-center gap-2">
                        <input type="file" accept="image/*" onChange={(e) => {
                          const file = e.target.files?.[0];
                          if (!file) return;
                          const reader = new FileReader();
                          reader.onload = () => {
                            const result = reader.result as string;
                            const match = result.match(/^data:(.+);base64,(.*)$/);
                            if (match) {
                              setProfileImageType(match[1]);
                              setProfileImageData(match[2]);
                              setProfileImageUrl('');
                            }
                          };
                          reader.readAsDataURL(file);
                        }} />
                        <input type="url" className="px-3 py-2 rounded-md border flex-1" placeholder="Or image URL" value={profileImageUrl || ''} onChange={(e) => { setProfileImageUrl(e.target.value); setProfileImageData(null); setProfileImageType(null); }} />
                      </div>
                      {(profileImageData || profileImageUrl || currentUser.avatar) && (
                        <div className="mt-2">
                          <p className="text-xs text-stone-500 mb-1">Preview</p>
                          <img alt="profile preview" src={profileImageData ? `data:${profileImageType};base64,${profileImageData}` : (profileImageUrl || currentUser.avatar || '')} className="w-24 h-24 rounded-full object-cover" />
                        </div>
                      )}
                    </div>
                    {editError && <div className="text-red-500 text-sm">{editError}</div>}
                    <div className="flex gap-2 mt-1">
                      <button disabled={editLoading} onClick={async () => {
                        setEditLoading(true); setEditError(null);
                        try {
                          if (!onUpdateProfile) throw new Error('No update handler configured');
                          const payload: any = { name: editName, email: editEmail };
                          if (profileImageData && profileImageType) { payload.profileImageData = profileImageData; payload.profileImageType = profileImageType; }
                          if (profileImageUrl) payload.profileImageUrl = profileImageUrl;
                          const updated = await onUpdateProfile(payload);
                          if (!updated) {
                            setEditError('Failed to update profile');
                          } else {
                            setIsEditing(false);
                          }
                        } catch (err: any) {
                          setEditError(err?.message || 'Update failed');
                        } finally { setEditLoading(false); }
                      }} className="px-3 py-1 rounded-md bg-amber-500 text-white">{editLoading ? 'Saving…' : 'Save'}</button>
                      <button disabled={editLoading} onClick={() => { setIsEditing(false); setEditName(currentUser.name || ''); setEditEmail(currentUser.email || ''); setEditError(null); }} className="px-3 py-1 rounded-md border">Cancel</button>
                    </div>
