function PetFormModal({ isOpen, onClose, onSubmit, darkMode, initialData }: { isOpen: boolean, onClose: () => void, onSubmit: (pet: Pet) => void, darkMode: boolean, initialData?: Pet }) {
  const [loadingBio, setLoadingBio] = useState(false);
  const [formData, setFormData] = useState({
    name: initialData?.name || "",
    type: initialData?.type || "Dog" as PetType,
    age: initialData?.age || "",
    location: initialData?.location || "",
    description: initialData?.description || "",
    imageUrl: initialData?.imageUrl || "",
    imageData: initialData?.imageData || null as string | null,
    imageType: initialData?.imageType || null as string | null,
    contactNumber: initialData?.contactNumber || "",
    contactName: initialData?.contactName || "",
    urgency: initialData?.urgency || "Medium" as UrgencyLevel,
    traits: initialData?.traits || "",
  });

  const generateBio = async () => {
    if (!formData.name || !formData.traits) return;
    setLoadingBio(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const res = await ai.models.generateContent({
          model: 'gemini-2.5-flash',
          contents: `Short adoption bio for a ${formData.type} named ${formData.name}. Traits: ${formData.traits}. Friendly tone.`
      });
      setFormData(prev => ({ ...prev, description: res.text.trim() }));
    } finally { setLoadingBio(false); }
  };

  const inputClass = `w-full p-3 rounded-xl border focus:ring-2 focus:ring-amber-500/50 outline-none ${darkMode ? "bg-stone-800 border-stone-700 text-white" : "bg-stone-50 border-stone-200"}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm overflow-y-auto">
      <div className={`rounded-2xl w-full max-w-lg shadow-2xl my-8 ${darkMode ? "bg-stone-900" : "bg-white"}`}>
        <div className="p-6 border-b flex justify-between items-center">
          <h2 className="text-xl font-bold">{initialData ? "Edit Listing" : "List a Stray Friend"}</h2>
          <button onClick={onClose}><X size={20} /></button>
        </div>
        <form onSubmit={(e) => {
          e.preventDefault();
          onSubmit({
            id: initialData?.id || Math.random().toString(36).substr(2, 9),
            ...formData,
            distance: Math.random() * 5,
            postedAt: initialData?.postedAt || new Date(),
            status: initialData?.status || "Available",
            comments: initialData?.comments || [],
            cheers: initialData?.cheers || 0,
          });
        }} className="p-6 space-y-4">
          <div className="grid grid-cols-2 gap-3">
            <div><label className="text-xs font-bold opacity-50 uppercase">Pet Name</label><input required className={inputClass} value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} /></div>
            <div><label className="text-xs font-bold opacity-50 uppercase">Type</label><select className={inputClass} value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})}><option>Dog</option><option>Cat</option><option>Bird</option><option>Rat</option><option>Other</option></select></div>
          </div>
          <div><label className="text-xs font-bold opacity-50 uppercase">Location Found</label><input required className={inputClass} placeholder="Neighborhood/Street" value={formData.location} onChange={e => setFormData({...formData, location: e.target.value})} /></div>

          <div className="p-4 border-2 border-dashed border-amber-200 rounded-xl space-y-3">
             <label className="text-xs font-bold text-amber-600 uppercase">Image URL (Preferred)</label>
             <input className={inputClass} type="url" placeholder="https://image-link.com/photo.jpg" value={formData.imageUrl} onChange={e => setFormData({...formData, imageUrl: e.target.value, imageData: null})} />
             <div className="text-center text-[10px] opacity-40">OR UPLOAD FILE</div>
             <input type="file" accept="image/*" onChange={e => {
                const file = e.target.files?.[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = () => {
                   const match = (reader.result as string).match(/^data:(.+);base64,(.*)$/);
                   if (match) setFormData({...formData, imageData: match[2], imageType: match[1], imageUrl: ""});
                };
                reader.readAsDataURL(file);
             }} />
          </div>

          <div className="grid grid-cols-2 gap-3">
             <div><label className="text-xs font-bold opacity-50 uppercase">Your Name</label><input required className={inputClass} value={formData.contactName} onChange={e => setFormData({...formData, contactName: e.target.value})} /></div>
             <div><label className="text-xs font-bold opacity-50 uppercase">WhatsApp No.</label><input required type="tel" className={inputClass} placeholder="e.g. 917905..." value={formData.contactNumber} onChange={e => setFormData({...formData, contactNumber: e.target.value})} /></div>
          </div>

          <div className="p-4 bg-amber-50 dark:bg-stone-800 rounded-xl border border-amber-100 space-y-3">
             <label className="text-xs font-bold text-amber-600 uppercase flex items-center gap-2"><Sparkles size={14}/> AI Description Generator</label>
             <input className={inputClass} placeholder="Traits: playful, small, hungry..." value={formData.traits} onChange={e => setFormData({...formData, traits: e.target.value})} />
             <button type="button" onClick={generateBio} disabled={loadingBio || !formData.traits} className="text-xs bg-amber-500 text-white px-3 py-1 rounded-md font-bold">Generate Bio</button>
             <textarea required className={inputClass} rows={3} placeholder="Tell their story..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
          </div>
          <button type="submit" className="w-full bg-amber-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-amber-700 shadow-lg">Save Listing</button>
        </form>
      </div>
    </div>
  );
}

const rootElement = document.getElementById("root");
if (!rootElement) throw new Error('Root element not found');
createRoot(rootElement).render(<App />);

