// --- Recommendation Modal Component ---
function RecommendationModal({ isOpen, onClose, pets, onRecommend, darkMode }: { isOpen: boolean, onClose: () => void, pets: Pet[], onRecommend: (ids: string[]) => void, darkMode: boolean }) {
    const [step, setStep] = useState(1);
    const [answers, setAnswers] = useState({ type: 'Any', energy: 'Moderate', space: 'Small' });
    if (!isOpen) return null;
    const handleFinish = () => {
        const matches = pets.filter(pet => {
            let score = 0;
            if (answers.type === 'Any' || pet.type === answers.type) score += 2;
            const text = (pet.traits + ' ' + pet.description).toLowerCase();
            if (answers.energy === 'Active' && (text.includes('playful') || text.includes('energetic'))) score += 1;
            if (answers.energy === 'Chill' && (text.includes('calm') || text.includes('senior'))) score += 1;
            return score >= 2;
        });
        onRecommend(matches.map(p => p.id));
    };
    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className={`p-6 rounded-2xl shadow-2xl w-full max-w-md ${darkMode ? "bg-stone-900 text-white" : "bg-white text-stone-800"}`}>
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-xl font-bold flex items-center gap-2"><Sparkles className="text-amber-500" /> Match Quiz</h2>
                    <button onClick={onClose}><X size={24} /></button>
                </div>
                {step === 1 && (
                    <div className="space-y-4">
                        <h3 className="text-lg font-bold">What kind of friend?</h3>
                        <div className="grid grid-cols-2 gap-2">
                            {['Dog', 'Cat', 'Bird', 'Any'].map(t => <button key={t} onClick={() => setAnswers({...answers, type: t as any})} className={`p-4 border-2 rounded-xl font-bold ${answers.type === t ? 'border-amber-500 bg-amber-50' : ''}`}>{t}</button>)}
                        </div>
                        <button onClick={() => setStep(2)} className="w-full bg-stone-900 text-white py-3 rounded-xl font-bold">Next</button>
                    </div>
                )}
                {step === 2 && (
                    <div className="space-y-4">
                        <h3 className="text-lg font-bold">Your Energy?</h3>
                        <div className="space-y-2">
                            {['Chill', 'Moderate', 'Active'].map(e => <button key={e} onClick={() => setAnswers({...answers, energy: e as any})} className={`w-full p-4 border-2 rounded-xl font-bold ${answers.energy === e ? 'border-amber-500 bg-amber-50' : ''}`}>{e}</button>)}
                        </div>
                        <div className="flex gap-2">
                             <button onClick={() => setStep(1)} className="flex-1 py-3 border rounded-xl">Back</button>
                             <button onClick={handleFinish} className="flex-2 bg-amber-500 text-white py-3 rounded-xl font-bold px-8">Find Matches</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

// --- AI Chat Bot Component ---
function AIChatBot({ onClose, darkMode }: { onClose: () => void, darkMode: boolean }) {
  const [messages, setMessages] = useState<{role: 'user' | 'model', text: string}[]>([{ role: 'model', text: "Hello! Ask me about street animal care." }]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const chatRef = useRef<any>(null);

  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: { systemInstruction: "StreetPaws Assistant. Advice on street animal care. Brief and kind." }
    });
  }, []);

  useEffect(() => { scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight); }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    const msg = input;
    setInput("");
    setMessages(prev => [...prev, { role: 'user', text: msg }]);
    setLoading(true);
    try {
      const result = await chatRef.current.sendMessage({ message: msg });
      setMessages(prev => [...prev, { role: 'model', text: result.text }]);
    } catch {
      setMessages(prev => [...prev, { role: 'model', text: "Error. Try again later." }]);
    } finally { setLoading(false); }
  };

  return (
    <div className={`fixed bottom-24 right-6 w-80 sm:w-96 rounded-2xl shadow-2xl flex flex-col overflow-hidden z-50 border animate-in slide-in-from-bottom-5 ${darkMode ? "bg-stone-800 border-stone-700 text-stone-100" : "bg-white border-stone-200 text-stone-800"}`} style={{ height: "450px" }}>
      <div className="p-4 bg-amber-600 text-white flex justify-between items-center font-bold">
         <span className="flex items-center gap-2"><Stethoscope size={18} /> AI Assistant</span>
         <button onClick={onClose}><X size={18} /></button>
      </div>
      <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
        {messages.map((m, i) => <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}><div className={`p-3 rounded-xl text-sm ${m.role === 'user' ? "bg-amber-500 text-white" : (darkMode ? "bg-stone-700" : "bg-stone-100")}`}>{m.text}</div></div>)}
        {loading && <div className="text-xs text-center animate-pulse">Thinking...</div>}
      </div>
      <div className="p-3 border-t flex gap-2">
        <input value={input} onChange={(e) => setInput(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSend()} placeholder="Ask advice..." className={`flex-1 px-3 py-2 rounded-lg text-sm border focus:outline-none ${darkMode ? "bg-stone-900 border-stone-600" : "bg-stone-50"}`} />
        <button onClick={handleSend} disabled={loading} className="p-2 bg-amber-600 text-white rounded-lg"><Send size={18} /></button>
      </div>
    </div>
  );
}

