            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="text-xs font-semibold mb-1 block">Pet's Name *</label>
                <input required className={inputClass} placeholder="e.g. Buddy" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div>
                <label className="text-xs font-semibold mb-1 block">Animal Type *</label>
                <select className={inputClass} value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})}>
