                        type="button" 
                        onClick={generateBio} 
                        disabled={loadingBio || !formData.traits} 
                        className="bg-amber-500 text-white px-5 rounded-xl text-sm font-bold hover:bg-amber-600 disabled:opacity-50 transition-all active:scale-95 shadow-lg shadow-amber-500/30"
                      >
                        {loadingBio ? "Wait..." : "Write"}
                     </button>
                   </div>
                </div>
                <div>
                   <label className="text-[11px] font-bold opacity-50 block mb-1">Story / Description *</label>
                   <textarea required className={`${inputClass} resize-none`} rows={3} placeholder="Tell us about the pet..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                </div>
             </div>
          </section>

          {/* Section 4: Contact & Location */}
          <section>
             <h3 className={sectionTitleClass}><Phone size={14}/> Contact & Help</h3>
             <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                   <label className="text-xs font-semibold mb-1 block">Location Details *</label>
                   <div className="relative">
                      <input required className={`${inputClass} pl-10`} placeholder="e.g. Near Market St." value={formData.location} onChange={e => setFormData({...formData, location: e.target.value})} />
                      <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
                   </div>
                </div>
                <div>
                   <label className="text-xs font-semibold mb-1 block">Your Name *</label>
                   <div className="relative">
                      <input required className={`${inputClass} pl-10`} placeholder="e.g. John Doe" value={formData.contactName} onChange={e => setFormData({...formData, contactName: e.target.value})} />
                      <User className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
                   </div>
                </div>
                <div className="sm:col-span-2">
                   <label className="text-xs font-semibold mb-1 block">WhatsApp Phone Number *</label>
                   <div className="relative">
                      <input required type="tel" className={`${inputClass} pl-10`} placeholder="e.g. 917905013678 (incl. country code)" value={formData.contactNumber} onChange={e => setFormData({...formData, contactNumber: e.target.value})} />
                      <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
                   </div>
                </div>
             </div>
          </section>

          {/* Submit */}
          <div className="pt-4 sticky bottom-0 bg-inherit pb-2">
             <button type="submit" className="w-full bg-gradient-to-r from-amber-500 to-orange-600 text-white py-4 rounded-2xl font-black text-lg hover:shadow-2xl hover:shadow-orange-500/20 transform hover:-translate-y-0.5 active:translate-y-0 transition-all">
                {initialData ? "Update Pet Record" : "Publish Pet Listing"}
             </button>
          </div>
        </form>
      </div>
    </div>
  );
}

const rootElement = document.getElementById("root");
if (!rootElement) throw new Error('Root element not found');
createRoot(rootElement).render(<App />);

