  postedAt: Date;
  urgency: UrgencyLevel;
  status: PetStatus;
  donationUrl?: string;
  traits: string;
  comments: Comment[];
  cheers: number;
}

interface Toast {
  id: string;
  message: string;
  type: "success" | "error" | "info";
}

