              <h3 className="text-sm font-black mb-4 flex items-center gap-2"><div className="w-6 h-6 rounded-lg bg-blue-100 dark:bg-blue-900/30 text-blue-600 flex items-center justify-center"><User size={14}/></div> Identitiy</h3>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className={labelStyles}>Pet Name *</label>
                  <input required className={inputStyles} placeholder="What should we call them?" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
