                </div>
              </div>
            </section>

            <section>
              <h3 className="text-sm font-black mb-4 flex items-center gap-2"><div className="w-6 h-6 rounded-lg bg-red-100 dark:bg-red-900/30 text-red-600 flex items-center justify-center"><ImageIcon size={14}/></div> Visuals</h3>
