function AIChatBot({ onClose, darkMode }: { onClose: () => void, darkMode: boolean }) {
  const [messages, setMessages] = useState<{role: 'user' | 'model', text: string}[]>([{ role: 'model', text: "Hello! Ask me about street animal first aid or local care tips." }]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const chatRef = useRef<any>(null);

  useEffect(() => {
    // Correct usage: Initialize GoogleGenAI instance with apiKey named parameter
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: { systemInstruction: "StreetPaws Emergency/Care AI. Expert in stray animal welfare. Short, helpful responses." }
    });
  }, []);

  useEffect(() => { scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight); }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    const msg = input; setInput(""); setMessages(p => [...p, { role: 'user', text: msg }]); setLoading(true);
    try {
      // Correct usage: Use chat.sendMessage for stateful conversation
      const result = await chatRef.current.sendMessage({ message: msg });
      // Correct usage: Access .text property directly
      setMessages(p => [...p, { role: 'model', text: result.text || "I'm sorry, I couldn't generate a response." }]);
    } catch (error) {
      console.error("AI Chat Error:", error);
      setMessages(p => [...p, { role: 'model', text: "Error connecting. Try again." }]); 
    } finally { setLoading(false); }
  };

  return (
    <div className={`fixed bottom-24 right-6 w-[calc(100vw-3rem)] sm:w-96 rounded-[2rem] shadow-[0_32px_64px_-12px_rgba(0,0,0,0.5)] flex flex-col overflow-hidden z-50 border-4 animate-in slide-in-from-bottom-10 duration-500 ${darkMode ? "bg-stone-800 border-stone-700 text-stone-100" : "bg-white border-white text-stone-800"}`} style={{ height: "450px" }}>
      <div className="p-5 bg-amber-600 text-white flex justify-between items-center font-black">
         <span className="flex items-center gap-2"><Stethoscope size={20} /> AI STRAY-VET</span>
         <button onClick={onClose} className="p-1 hover:rotate-90 transition-transform"><X size={20} /></button>
      </div>
      <div className="flex-1 overflow-y-auto p-5 space-y-4 no-scrollbar" ref={scrollRef}>
        {messages.map((m, i) => <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}><div className={`p-4 rounded-2xl text-xs sm:text-sm font-medium leading-relaxed ${m.role === 'user' ? "bg-amber-500 text-white shadow-lg shadow-amber-500/20" : darkMode ? "bg-stone-700" : "bg-stone-100"}`}>{m.text}</div></div>)}
        {loading && <div className="text-[10px] text-center font-bold opacity-30 animate-pulse uppercase tracking-widest">Consulting Medical Database...</div>}
      </div>
      <div className="p-4 border-t flex gap-2">
        <input value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSend()} placeholder="Injured dog tips..." className={`flex-1 px-4 py-3 rounded-2xl text-sm outline-none border transition-all ${darkMode ? "bg-stone-900 border-stone-600" : "bg-stone-50 border-stone-100"}`} />
        <button onClick={handleSend} disabled={loading} className="p-3 bg-amber-600 text-white rounded-2xl shadow-lg active:scale-90 transition-transform"><Send size={18} /></button>
      </div>
    </div>
  );
}

