// --- Helpers ---
const normalizePet = (p: any): Pet => ({
  id: String(p.id || Math.random().toString(36).substr(2, 9)),
  name: p.name || "",
  type: (p.type as PetType) || "Other",
  age: p.age || "",
  location: p.location || "",
  distance: typeof p.distance === 'number' ? p.distance : Math.random() * 10,
  description: p.description || "",
  imageUrl: p.imageUrl || "",
  contactNumber: p.contactNumber || "",
  contactName: p.contactName || "Anonymous",
  postedAt: p.postedAt ? new Date(p.postedAt) : new Date(),
  urgency: (p.urgency as UrgencyLevel) || "Medium",
  status: (p.status as PetStatus) || "Available",
  donationUrl: p.donationUrl || undefined,
  traits: p.traits || "",
  comments: Array.isArray(p.comments) ? p.comments : [],
  cheers: typeof p.cheers === 'number' ? p.cheers : 0,
});

const urgencyScore = (u: UrgencyLevel) => {
  switch (u) {
    case "Critical": return 4;
    case "High": return 3;
    case "Medium": return 2;
    case "Low": return 1;
    default: return 0;
  }
};

// --- Main App Component ---

function App() {
  const [pets, setPets] = useState<Pet[]>(INITIAL_PETS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isRecModalOpen, setIsRecModalOpen] = useState(false);
  const [editingPet, setEditingPet] = useState<Pet | null>(null);
  const [selectedType, setSelectedType] = useState<FilterType>("All");
  const [recommendedPetIds, setRecommendedPetIds] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [sortBy, setSortBy] = useState<SortOption>("Newest");
  const [viewMode, setViewMode] = useState<ViewMode>("grid");
  const [darkMode, setDarkMode] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [posterPet, setPosterPet] = useState<Pet | null>(null);
  const [toasts, setToasts] = useState<Toast[]>([]);

  // Lock body scroll when any major modal is active to prevent double scrollbars
  useEffect(() => {
    if (isModalOpen || isRecModalOpen || posterPet) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "unset";
    }
  }, [isModalOpen, isRecModalOpen, posterPet]);

  useEffect(() => {
    const savedPets = localStorage.getItem("streetpaws_local_pets");
    if (savedPets) {
      try {
        const parsed = JSON.parse(savedPets);
        setPets(parsed.map((p: any) => ({...normalizePet(p), postedAt: new Date(p.postedAt)})));
      } catch (e) {
        console.error("Failed to load local pets", e);
      }
    }
  }, []);

  const savePetsLocally = (newPets: Pet[]) => {
    localStorage.setItem("streetpaws_local_pets", JSON.stringify(newPets));
  };

  const addToast = (message: string, type: Toast["type"] = "info") => {
    const id = Math.random().toString(36);
    setToasts((prev) => [...prev, { id, message, type }]);
    setTimeout(() => setToasts((prev) => prev.filter((t) => t.id !== id)), 3000);
  };

  const [favorites, setFavorites] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem("streetpaws_favorites");
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const toggleFavorite = (petId: string) => {
    setFavorites((prev) => {
      const newFavs = prev.includes(petId) ? prev.filter(id => id !== petId) : [...prev, petId];
      localStorage.setItem("streetpaws_favorites", JSON.stringify(newFavs));
      return newFavs;
    });
    addToast(favorites.includes(petId) ? "Removed from favorites" : "Added to favorites", "success");
  };

  const handleAddComment = (petId: string, text: string) => {
    const newComment: Comment = { id: Math.random().toString(36), text, author: 'Community Member', createdAt: new Date() };
    const updatedPets = pets.map(p => p.id === petId ? { ...p, comments: [...p.comments, newComment] } : p);
    setPets(updatedPets);
    savePetsLocally(updatedPets);
    addToast("Note added!", "success");
  };

  const handleCheer = (petId: string) => {
    const updatedPets = pets.map(p => p.id === petId ? { ...p, cheers: p.cheers + 1 } : p);
    setPets(updatedPets);
    savePetsLocally(updatedPets);
  };

  const handleStatusChange = (petId: string, status: PetStatus) => {
     const updatedPets = pets.map(p => p.id === petId ? { ...p, status } : p);
     setPets(updatedPets);
     savePetsLocally(updatedPets);
     addToast(`Status updated to ${status}`, "success");
  };

  const handleSavePet = async (petData: Pet) => {
    const updatedPets = editingPet ? pets.map(p => p.id === petData.id ? petData : p) : [petData, ...pets];
    setPets(updatedPets);
    savePetsLocally(updatedPets);
    addToast(editingPet ? 'Listing updated!' : 'Pet listed successfully!', 'success');
    setIsModalOpen(false);
    setEditingPet(null);
  };

  const openEditPetModal = (pet: Pet) => {
    setEditingPet(pet);
    setIsModalOpen(true);
  };

  const filteredPets = pets.filter((pet) => {
    if (selectedType === "Recommended") return recommendedPetIds.includes(pet.id);
    const matchesType = selectedType === "All" || (selectedType === "Favorites" && favorites.includes(pet.id)) || (selectedType === "Urgent" && (pet.urgency === "High" || pet.urgency === "Critical")) || pet.type === selectedType;
    return matchesType && (pet.name.toLowerCase().includes(searchTerm.toLowerCase()) || pet.location.toLowerCase().includes(searchTerm.toLowerCase()));
  });

  const sortedPets = [...filteredPets].sort((a, b) => {
    if (a.status === "Adopted" && b.status !== "Adopted") return 1;
    if (b.status === "Adopted" && a.status !== "Adopted") return -1;
    if (sortBy === "Newest") return b.postedAt.getTime() - a.postedAt.getTime();
    if (sortBy === "Urgency") return urgencyScore(b.urgency) - urgencyScore(a.urgency);
    if (sortBy === "Name") return a.name.localeCompare(b.name);
    return 0;
  });

  return (
    <div className={`min-h-screen font-sans transition-colors duration-300 ${darkMode ? "bg-stone-900 text-stone-100" : "bg-stone-50 text-stone-800"}`}>

      {/* Toast Overlay */}
      <div className="fixed top-20 right-4 z-[100] space-y-2 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className={`pointer-events-auto px-4 py-3 rounded-2xl shadow-xl flex items-center gap-2 animate-in slide-in-from-right-10 ${toast.type === "success" ? "bg-green-600 text-white" : "bg-stone-800 text-white"}`}>
