        {toasts.map(toast => (
          <div key={toast.id} className={`pointer-events-auto px-4 py-3 rounded-2xl shadow-xl flex items-center gap-2 animate-in slide-in-from-right-10 ${toast.type === "success" ? "bg-green-600 text-white" : "bg-stone-800 text-white"}`}>
            {toast.type === "success" && <CheckCircle2 size={16} />}
            <span className="text-sm font-semibold">{toast.message}</span>
          </div>
        ))}
      </div>

      {/* Header */}
      <header className={`border-b shadow-sm transition-colors sticky top-0 z-40 px-4 h-16 flex items-center justify-between ${darkMode ? "bg-stone-900 border-stone-800" : "bg-white border-stone-200"}`}>
        <button onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})} className="flex items-center gap-2">
          <div className="w-8 h-8 sm:w-10 h-10 bg-amber-500 rounded-full flex items-center justify-center text-white">
            <PawPrint size={18} className="sm:size-[22px]" />
          </div>
          <h1 className="text-lg sm:text-xl font-black tracking-tight">
            Street<span className="text-amber-500">Paws</span>
          </h1>
        </button>

        <div className="flex items-center gap-2 sm:gap-4">
          <button onClick={() => setDarkMode(!darkMode)} className={`p-2 rounded-full transition-colors ${darkMode ? "bg-stone-800 text-amber-400" : "bg-stone-100 text-stone-600"}`}>
            {darkMode ? <Sun size={18} /> : <Moon size={18} />}
          </button>
          <button onClick={() => {setEditingPet(null); setIsModalOpen(true);}} className="bg-amber-600 text-white px-3 sm:px-5 py-2 rounded-full font-bold text-xs sm:text-sm hover:bg-amber-700 transition-all flex items-center gap-2 shadow-lg active:scale-95">
            <Plus size={16} />
            <span className="hidden xs:inline">List Stray</span>
          </button>
        </div>
      </header>

      {/* Hero Section */}
      <section className={`py-12 sm:py-20 px-4 text-center relative overflow-hidden transition-colors ${darkMode ? "bg-stone-800/50" : "bg-amber-50"}`}>
