      <main className="max-w-7xl mx-auto px-4 py-6 sm:py-10">
        <div className="flex flex-col gap-4 mb-8">
          <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar scroll-smooth">
            {["All", "Favorites", "Urgent", "Recommended", "Dog", "Cat", "Bird", "Other"].map((type) => (
              <button
                key={type}
                onClick={() => { setSelectedType(type as FilterType); if (type !== 'Recommended') setRecommendedPetIds([]); }}
                className={`px-4 py-2.5 rounded-full text-xs sm:text-sm font-bold whitespace-nowrap transition-all border shrink-0 flex items-center gap-2 ${selectedType === type ? "bg-amber-500 text-white border-amber-500 shadow-lg shadow-amber-500/20" : darkMode ? "bg-stone-800 border-stone-700 text-stone-400" : "bg-white border-stone-200 text-stone-600"}`}
              >
                {type === "Favorites" && <Heart size={14} className={selectedType === "Favorites" ? "fill-white" : ""} />}
                {type}
              </button>
            ))}
          </div>

          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
              <input
                type="text"
                placeholder="Search location..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className={`w-full pl-12 pr-4 py-3.5 rounded-2xl border transition-all text-sm outline-none focus:ring-2 focus:ring-amber-500/30 ${darkMode ? "bg-stone-800 border-stone-600 text-white" : "bg-white border-stone-200"}`}
              />
            </div>
            <div className="flex gap-2">
              <select
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value as SortOption)}
                className={`flex-1 sm:w-40 px-4 py-3.5 rounded-2xl border font-bold text-sm outline-none transition-all ${darkMode ? "bg-stone-800 border-stone-600" : "bg-white border-stone-200"}`}
              >
                <option value="Newest">Recent</option>
                <option value="Urgency">Urgency</option>
                <option value="Name">Name</option>
              </select>
              <div className={`hidden xs:flex p-1 rounded-2xl border ${darkMode ? "bg-stone-800 border-stone-600" : "bg-white border-stone-200"}`}>
                <button onClick={() => setViewMode("grid")} className={`p-2 rounded-xl ${viewMode === "grid" ? (darkMode ? "bg-stone-700" : "bg-stone-100") : "opacity-40"}`}><Grid size={20} /></button>
                <button onClick={() => setViewMode("list")} className={`p-2 rounded-xl ${viewMode === "list" ? (darkMode ? "bg-stone-700" : "bg-stone-100") : "opacity-40"}`}><List size={20} /></button>
              </div>
            </div>
          </div>
        </div>

        <div className={`grid gap-4 sm:gap-6 ${viewMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1'}`}>
          {sortedPets.map((pet) => (
            <PetCard
              key={pet.id}
              pet={pet}
              darkMode={darkMode}
              viewMode={viewMode}
              isFavorite={favorites.includes(pet.id)}
              onToggleFavorite={() => toggleFavorite(pet.id)}
              onGeneratePoster={() => setPosterPet(pet)}
              onAddComment={handleAddComment}
              onCheer={handleCheer}
              onStatusChange={handleStatusChange}
              onEdit={() => openEditPetModal(pet)}
              onDelete={() => { if(confirm("Delete this listing?")) { const updated = pets.filter(p => p.id !== pet.id); setPets(updated); savePetsLocally(updated); addToast("Listing deleted", "info"); }}}
            />
          ))}
        </div>

        {sortedPets.length === 0 && (
            <div className={`py-20 text-center rounded-[2.5rem] border-2 border-dashed ${darkMode ? "border-stone-800 text-stone-600" : "border-stone-200 text-stone-400"}`}>
              <div className="mb-4 flex justify-center"><ImageIcon size={48} className="opacity-20" /></div>
              <p className="text-lg font-bold">No friends found.</p>
            </div>
        )}
      </main>

      {/* Floating Action Button for Mobile */}
      <button onClick={() => {setEditingPet(null); setIsModalOpen(true);}} className="sm:hidden fixed bottom-6 right-6 w-14 h-14 bg-amber-600 text-white rounded-full shadow-2xl flex items-center justify-center z-40 active:scale-90 transition-transform">
        <Plus size={24} />
      </button>

      {isModalOpen && (
        <PetFormModal
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          onSubmit={handleSavePet}
          darkMode={darkMode}
          initialData={editingPet || undefined}
        />
      )}

      {posterPet && <PosterModal pet={posterPet} onClose={() => setPosterPet(null)} darkMode={darkMode} />}

      {isRecModalOpen && (
        <RecommendationModal
          isOpen={isRecModalOpen}
          onClose={() => setIsRecModalOpen(false)}
          pets={pets}
          onRecommend={(ids) => {
            setRecommendedPetIds(ids);
            setSelectedType("Recommended");
            setIsRecModalOpen(false);
          }}
          darkMode={darkMode}
        />
      )}

      <footer className={`mt-10 py-10 border-t ${darkMode ? "border-stone-800" : "border-stone-200"}`}>
        <div className="max-w-7xl mx-auto px-4 flex flex-col items-center gap-4 text-center">
          <div className="flex items-center gap-2 font-black text-amber-500">
            <PawPrint size={20} /> StreetPaws Community
          </div>
          <p className="text-sm opacity-60 max-w-sm">Every stray animal listed here is looking for a human like you. Help us by sharing these listings.</p>
          <div className="space-y-1">
            <p className="text-sm font-bold text-stone-900 dark:text-stone-100">Developed by Gopal Patel</p>
            <p className="text-xs opacity-50">Contact for developing professional websites: <a href="mailto:patelgopal563@gmail.com" className="text-amber-500 hover:underline">patelgopal563@gmail.com</a></p>
          </div>
        </div>
      </footer>
    </div>
  );
}

// --- Pet Listing Form Modal ---

function PetFormModal({ isOpen, onClose, onSubmit, darkMode, initialData }: { isOpen: boolean, onClose: () => void, onSubmit: (pet: Pet) => void, darkMode: boolean, initialData?: Pet }) {
  const [loadingBio, setLoadingBio] = useState(false);
  const [formData, setFormData] = useState({
    name: initialData?.name || "",
    type: initialData?.type || ("Dog" as PetType),
    age: initialData?.age || "",
    location: initialData?.location || "",
    description: initialData?.description || "",
    imageUrl: initialData?.imageUrl || "",
    contactNumber: initialData?.contactNumber || "",
    contactName: initialData?.contactName || "",
    urgency: initialData?.urgency || ("Medium" as UrgencyLevel),
    traits: initialData?.traits || "",
  });

  const generateBio = async () => {
    if (!formData.name || !formData.traits) return;
    setLoadingBio(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const res = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Create a professional, heartwarming 2-sentence adoption bio for a stray ${formData.type} named ${formData.name}. Traits: ${formData.traits}. Highlight empathy and community help.`
      });
      setFormData(prev => ({ ...prev, description: res.text?.trim() || "" }));
    } catch {
      alert("AI generator failed. Please write manually.");
    } finally { setLoadingBio(false); }
  };

  const inputStyles = `w-full p-4 rounded-2xl border font-medium text-base sm:text-sm transition-all outline-none focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 ${
    darkMode 
      ? "bg-stone-800 border-stone-600 text-white placeholder-stone-500" 
      : "bg-stone-50 border-stone-200 text-stone-800 placeholder-stone-400"
  }`;

  const labelStyles = `text-[11px] font-black uppercase tracking-widest mb-2 block px-1 ${
    darkMode ? "text-stone-300" : "text-stone-400"
  }`;

  return (
    <div className="fixed inset-0 z-[100] flex flex-col sm:items-center sm:justify-center bg-black/80 backdrop-blur-md overflow-hidden animate-in fade-in duration-300">
      <div className={`flex flex-col w-full h-full sm:h-auto sm:max-h-[90vh] sm:max-w-xl sm:rounded-[2.5rem] shadow-2xl animate-in zoom-in-95 slide-in-from-bottom-10 duration-500 ${darkMode ? "bg-stone-900" : "bg-white"}`}>

        <div className={`p-6 border-b flex justify-between items-center shrink-0 ${darkMode ? "border-stone-800 bg-stone-900 text-white" : "border-stone-100 bg-white"}`}>
          <div>
             <h2 className="text-xl sm:text-2xl font-black">{initialData ? "Edit Pet Details" : "Create New Listing"}</h2>
             <div className="flex items-center gap-1 text-[10px] font-bold uppercase tracking-widest text-amber-500">
                <Sparkles size={10} /> StreetPaws Verified
             </div>
          </div>
          <button onClick={onClose} className={`p-3 rounded-full hover:scale-110 active:scale-90 transition-transform ${darkMode ? "bg-stone-800 text-white" : "bg-stone-100 text-stone-900"}`}>
            <X size={20} />
          </button>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); onSubmit({ ...normalizePet(initialData || {}), ...formData, postedAt: initialData?.postedAt || new Date() }); }} className="flex-1 overflow-y-auto p-6 space-y-8 no-scrollbar scrollbar-hide pb-24">
          <div className="space-y-6">
            <section>
              <h3 className="text-sm font-black mb-4 flex items-center gap-2 text-blue-500"><User size={16}/> Identity</h3>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className={labelStyles}>Pet Name *</label>
                  <input required className={inputStyles} placeholder="Buddy, Fluffy..." value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
                <div>
                  <label className={labelStyles}>Animal Type *</label>
                  <select className={inputStyles} value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})}>
                    <option>Dog</option>
                    <option>Cat</option>
                    <option>Bird</option>
                    <option>Rat</option>
                    <option>Other</option>
                  </select>
                </div>
              </div>
            </section>

            <section>
              <h3 className="text-sm font-black mb-4 flex items-center gap-2 text-red-500"><ImageIcon size={16}/> Visuals</h3>
              <div className="space-y-3">
                <label className={labelStyles}>Live Image URL *</label>
                <input required className={inputStyles} type="url" placeholder="https://..." value={formData.imageUrl} onChange={e => setFormData({...formData, imageUrl: e.target.value})} />
                {formData.imageUrl && (
                  <div className="relative aspect-video rounded-3xl overflow-hidden shadow-inner border border-stone-200 dark:border-stone-700 bg-stone-100 dark:bg-stone-800">
                    <img src={formData.imageUrl} alt="Pet Preview" className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = 'https://images.unsplash.com/photo-1543466835-00a7907e9de1?auto=format&fit=crop&q=80&w=800')} />
                    <div className="absolute top-2 right-2 bg-black/60 text-white text-[10px] px-2 py-1 rounded-full font-bold">PREVIEW</div>
                  </div>
                )}
              </div>
            </section>

            <section className={`p-6 rounded-[2rem] border-2 border-dashed ${darkMode ? "bg-stone-800/30 border-stone-600" : "bg-amber-50/50 border-amber-200"}`}>
               <div className="flex items-center justify-between mb-4">
                  <h3 className="text-sm font-black flex items-center gap-2 text-amber-600"><Sparkles size={16}/> AI Story Builder</h3>
               </div>
               <div className="space-y-4">
                  <div>
                    <label className={labelStyles}>Key Traits</label>
                    <div className="flex gap-2">
                      <input className={`${inputStyles} border-amber-500/30`} placeholder="Friendly, black coat..." value={formData.traits} onChange={e => setFormData({...formData, traits: e.target.value})} />
                      <button type="button" onClick={generateBio} disabled={loadingBio || !formData.traits} className="bg-amber-500 text-white px-6 rounded-2xl font-black text-sm hover:bg-amber-600 active:scale-95 disabled:opacity-30">
                        {loadingBio ? "..." : "AI"}
                      </button>
                    </div>
                  </div>
                  <div>
                    <label className={labelStyles}>Heartfelt Description *</label>
                    <textarea required className={`${inputStyles} resize-none border-amber-500/30`} rows={4} placeholder="Tell their story..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                  </div>
               </div>
            </section>

            <section>
              <h3 className="text-sm font-black mb-4 flex items-center gap-2 text-green-500"><Phone size={16}/> Connection</h3>
              <div className="space-y-4">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div>
                    <label className={labelStyles}>Found Near (Location) *</label>
                    <input required className={inputStyles} placeholder="Sector 5, Park..." value={formData.location} onChange={e => setFormData({...formData, location: e.target.value})} />
                  </div>
                  <div>
                    <label className={labelStyles}>Reporter Name *</label>
                    <input required className={inputStyles} placeholder="Your name" value={formData.contactName} onChange={e => setFormData({...formData, contactName: e.target.value})} />
                  </div>
                </div>
                <div>
                  <label className={labelStyles}>WhatsApp Number *</label>
                  <input required type="tel" className={inputStyles} placeholder="e.g. 917905013678" value={formData.contactNumber} onChange={e => setFormData({...formData, contactNumber: e.target.value})} />
                </div>
              </div>
            </section>
          </div>

          <div className={`absolute bottom-0 left-0 right-0 p-6 bg-inherit/95 backdrop-blur-md border-t ${darkMode ? "border-stone-800 bg-stone-900" : "border-stone-100 bg-white"}`}>
            <button type="submit" className="w-full bg-gradient-to-r from-amber-600 to-orange-600 text-white py-4 rounded-3xl font-black text-lg shadow-xl shadow-amber-500/20 active:scale-95 transition-all">
               {initialData ? "Update Listing" : "Publish Now"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

