        </div>

        <p className="text-sm leading-relaxed opacity-80 mb-6 line-clamp-3 italic">"{pet.description}"</p>

        <div className="mt-auto space-y-4">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-stone-100 dark:bg-stone-700 flex items-center justify-center font-black text-amber-500 text-sm">
                {pet.contactName.charAt(0)}
             </div>
             <div className="flex-1 min-w-0">
                <p className="text-[10px] font-black uppercase tracking-widest opacity-40">Reported By</p>
                <p className="text-sm font-bold truncate">{pet.contactName}</p>
             </div>
          </div>

          <div className="grid grid-cols-2 gap-2">
            <a href={`https://wa.me/${pet.contactNumber}?text=${waMsg}`} target="_blank" rel="noreferrer" className="flex items-center justify-center gap-2 bg-[#25D366] text-white py-3 rounded-2xl font-bold text-sm shadow-lg shadow-green-500/20 hover:scale-105 active:scale-95 transition-all">
              <MessageCircle size={18} /> Chat
            </a>
            <button onClick={onGeneratePoster} className="flex items-center justify-center gap-2 bg-stone-900 text-white py-3 rounded-2xl font-bold text-sm shadow-lg hover:scale-105 active:scale-95 transition-all">
              <Printer size={18} /> Poster
            </button>
          </div>

          <div className="pt-4 border-t border-stone-100 dark:border-stone-700 flex justify-between items-center">
             <div className="flex gap-4">
                <button onClick={() => onCheer(pet.id)} className="flex items-center gap-1.5 text-xs font-bold hover:text-amber-500 transition-colors">
                  <Sparkles size={14} className={pet.cheers > 0 ? "text-amber-500" : ""} /> {pet.cheers} Cheers
                </button>
                <button onClick={() => setShowComments(!showComments)} className="flex items-center gap-1.5 text-xs font-bold hover:text-stone-900 dark:hover:text-white transition-colors">
                  <MessageCircle size={14} /> {pet.comments.length} Notes
                </button>
             </div>
             <select className="bg-transparent border-none text-[10px] font-black uppercase tracking-tighter text-amber-600 outline-none" value={pet.status} onChange={(e) => onStatusChange(pet.id, e.target.value as PetStatus)}>
                <option value="Available">Available</option>
                <option value="Adopted">Adopted</option>
                <option value="Fostered">Fostered</option>
             </select>
          </div>

          {showComments && (
            <div className="animate-in slide-in-from-top-2 duration-300">
               <div className="space-y-2 mb-3 max-h-32 overflow-y-auto pr-2 no-scrollbar">
                  {pet.comments.map(c => <div key={c.id} className={`p-2 rounded-xl text-[11px] ${darkMode ? "bg-stone-700/50" : "bg-stone-50"}`}>{c.text}</div>)}
               </div>
               <div className="flex gap-2">
                 <input value={newComment} onChange={e => setNewComment(e.target.value)} onKeyPress={e => e.key === 'Enter' && (onAddComment(pet.id, newComment), setNewComment(""))} placeholder="Add a note..." className={`flex-1 px-3 py-2 rounded-xl text-xs outline-none border focus:border-amber-500 ${darkMode ? "bg-stone-900 border-stone-700" : "bg-white"}`} />
                 <button onClick={() => { if(newComment.trim()){ onAddComment(pet.id, newComment); setNewComment(""); } }} className="p-2 bg-amber-500 text-white rounded-xl"><Send size={14}/></button>
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

