// --- Types ---
type PetType = "Dog" | "Cat" | "Bird" | "Rat" | "Other";
type SortOption = "Newest" | "Oldest" | "Name" | "Urgency";
type FilterType = PetType | "All" | "Favorites" | "Urgent" | "Recommended";
type ViewMode = "grid" | "list";
type UrgencyLevel = "Low" | "Medium" | "High" | "Critical";
type PetStatus = "Available" | "Adopted" | "Fostered";

interface Comment {
  id: string;
  text: string;
  createdAt: Date;
  author: string;
}

interface Pet {
  id: string;
  name: string;
  type: PetType;
  age: string;
  location: string;
  distance: number;
  description: string;
  imageUrl: string;
  contactNumber: string;
  contactName: string;
  postedAt: Date;
  urgency: UrgencyLevel;
  status: PetStatus;
  traits: string;
  comments: Comment[];
  cheers: number;
}

interface Toast {
  id: string;
  message: string;
  type: "success" | "error" | "info";
}

