const PetCard: React.FC<{
  pet: Pet;
  isFavorite: boolean;
  darkMode: boolean;
  viewMode: ViewMode;
  onToggleFavorite: () => void;
  onGeneratePoster: () => void;
  onAddComment: (id: string, text: string) => void;
  onCheer: (id: string) => void;
  onStatusChange: (id: string, status: PetStatus) => void;
  onEdit: () => void;
  onDelete: () => void;
}> = ({ pet, isFavorite, darkMode, viewMode, onToggleFavorite, onGeneratePoster, onAddComment, onCheer, onStatusChange, onEdit, onDelete }) => {
