  const [newComment, setNewComment] = useState("");
  const waMsg = encodeURIComponent(`Hi ${pet.contactName}, I'm interested in helping ${pet.name} (${pet.type}) that I saw on StreetPaws! Found at ${pet.location}.\n\nDescription: ${pet.description}`);

  const priorityColors = pet.urgency === "Critical" ? "bg-red-500 text-white" : pet.urgency === "High" ? "bg-orange-500 text-white" : pet.urgency === "Medium" ? "bg-amber-400 text-stone-900" : "bg-green-500 text-white";

  return (
    <div className={`group relative rounded-[2rem] overflow-hidden border-2 transition-all duration-500 flex flex-col ${darkMode ? "bg-stone-800 border-stone-800 hover:border-amber-500/50" : "bg-white border-white hover:border-amber-500/50 hover:shadow-2xl shadow-stone-200/50"}`}>

      <div className="relative aspect-[4/5] sm:aspect-[4/3] w-full overflow-hidden">
        <img
          src={pet.imageUrl || 'https://images.unsplash.com/photo-1543466835-00a7907e9de1?auto=format&fit=crop&q=80&w=800'}
          alt={pet.name}
          className={`w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110 ${pet.status === 'Adopted' ? 'grayscale opacity-60' : ''}`}
        />
        <div className="absolute top-4 left-4 z-10 flex flex-col gap-2">
          <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full shadow-lg ${priorityColors}`}>
            {pet.urgency}
          </span>
          {pet.status !== 'Available' && <span className="bg-stone-900 text-white text-[10px] font-black uppercase px-3 py-1.5 rounded-full shadow-lg">{pet.status}</span>}
        </div>
        <button onClick={onToggleFavorite} className="absolute top-4 right-4 p-3 bg-white/95 backdrop-blur-md rounded-full shadow-xl hover:scale-125 transition-all z-20">
          <Heart size={20} className={isFavorite ? "fill-red-500 text-red-500" : "text-stone-400"} />
        </button>
      </div>

      <div className="p-6 flex flex-col flex-1">
        <div className="flex justify-between items-start mb-1">
           <h3 className="text-2xl font-black truncate pr-4">{pet.name}</h3>
           <div className="flex gap-1 shrink-0">
             <button onClick={onEdit} className={`p-2 rounded-full transition-colors ${darkMode ? "hover:bg-stone-700 text-stone-400" : "hover:bg-stone-100 text-stone-400"}`}><Pencil size={16} /></button>
             <button onClick={onDelete} className="p-2 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-colors text-red-400"><Trash2 size={16} /></button>
           </div>
        </div>
        <p className="text-xs font-bold uppercase tracking-widest opacity-40 mb-3">{pet.type} • {pet.age || 'Street Friend'}</p>

        <div className="flex items-center gap-2 mb-4 text-sm opacity-70">
          <div className="w-8 h-8 rounded-full bg-amber-500/10 flex items-center justify-center text-amber-500"><MapPin size={16} /></div>
          <span className="truncate">{pet.location}</span>
        </div>

        <p className="text-sm leading-relaxed opacity-80 mb-6 line-clamp-3 italic">"{pet.description}"</p>

        <div className="mt-auto space-y-4">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-stone-100 dark:bg-stone-700 flex items-center justify-center font-black text-amber-500 text-sm">
                {pet.contactName.charAt(0)}
             </div>
             <div className="flex-1 min-w-0">
                <p className="text-[10px] font-black uppercase tracking-widest opacity-40">Reported By</p>
                <p className="text-sm font-bold truncate">{pet.contactName}</p>
             </div>
          </div>

          <div className="grid grid-cols-2 gap-2">
            <a href={`https://wa.me/${pet.contactNumber}?text=${waMsg}`} target="_blank" rel="noreferrer" className="flex items-center justify-center gap-2 bg-[#25D366] text-white py-3 rounded-2xl font-bold text-sm shadow-lg shadow-green-500/20 hover:scale-105 active:scale-95 transition-all">
              <MessageCircle size={18} /> Chat
