               </div>
               <div className="flex gap-2">
                 <input value={newComment} onChange={e => setNewComment(e.target.value)} onKeyPress={e => e.key === 'Enter' && (onAddComment(pet.id, newComment), setNewComment(""))} placeholder="Add a note..." className={`flex-1 px-3 py-2 rounded-xl text-xs outline-none border focus:border-amber-500 ${darkMode ? "bg-stone-900 border-stone-700" : "bg-white"}`} />
                 <button onClick={() => { if(newComment.trim()){ onAddComment(pet.id, newComment); setNewComment(""); } }} className="p-2 bg-amber-500 text-white rounded-xl"><Send size={14}/></button>
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

