  User,
  Phone,
  Moon,
  Sun,
  Grid,
  List,
  Download,
  Share2
} from "lucide-react";

// --- Types & Constants ---
type PetType = "Dog" | "Cat" | "Bird" | "Rat" | "Other";
type SortOption = "Newest" | "Oldest" | "Name" | "Urgency";
type FilterType = PetType | "All" | "Favorites" | "Urgent" | "Recommended";
type ViewMode = "grid" | "list";
type UrgencyLevel = "Low" | "Medium" | "High" | "Critical";
type PetStatus = "Available" | "Adopted" | "Fostered";

const EMOTIONAL_QUOTES = [
  "Every life matters.",
  "Be the voice for those who cannot speak.",
  "Love is a four-legged word.",
  "Saving one animal won't change the world, but it changes the world for them.",
  "Adoption is an act of pure love.",
  "A house is not a home without a street paw.",
  "Kindness starts with a small bowl of water and a big heart."
];

interface Comment {
  id: string;
  text: string;
  createdAt: Date;
  author: string;
}

interface Pet {
  id: string;
  name: string;
  type: PetType;
  age: string;
  location: string;
  distance: number;
  description: string;
  imageUrl: string;
  contactNumber: string;
  contactName: string;
  postedAt: Date;
  urgency: UrgencyLevel;
  status: PetStatus;
  traits: string;
  comments: Comment[];
  cheers: number;
}

interface Toast {
  id: string;
  message: string;
  type: "success" | "error" | "info";
}

// --- Mock Data ---
const INITIAL_PETS: Pet[] = [
  {
    id: "1",
    name: "Rusty",
    type: "Dog",
    age: "2 years",
    location: "Downtown Market Area",
    distance: 1.2,
    description: "Rusty is a gentle soul who loves watching people pass by. He's a bit shy at first but wags his tail furiously once he knows you have a biscuit. Needs a safe yard.",
