    comments: [{ id: "c1", text: "So happy she found a home!", author: "Neighbor", createdAt: new Date() }],
    cheers: 24,
  },
];

// --- Helpers ---
const normalizePet = (p: any): Pet => ({
  id: String(p.id || Math.random().toString(36).substr(2, 9)),
  name: p.name || "",
  type: (p.type as PetType) || "Other",
  age: p.age || "",
  location: p.location || "",
  distance: typeof p.distance === 'number' ? p.distance : Math.random() * 10,
  description: p.description || "",
  imageUrl: p.imageUrl || "",
  contactNumber: p.contactNumber || "",
  contactName: p.contactName || "Anonymous",
  postedAt: p.postedAt ? new Date(p.postedAt) : new Date(),
  urgency: (p.urgency as UrgencyLevel) || "Medium",
  status: (p.status as PetStatus) || "Available",
  traits: p.traits || "",
  comments: Array.isArray(p.comments) ? p.comments : [],
  cheers: typeof p.cheers === 'number' ? p.cheers : 0,
});

const urgencyScore = (u: UrgencyLevel) => {
  switch (u) {
    case "Critical": return 4;
    case "High": return 3;
    case "Medium": return 2;
    case "Low": return 1;
    default: return 0;
  }
};

// --- Main App Component ---

function App() {
  const [pets, setPets] = useState<Pet[]>(INITIAL_PETS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isRecModalOpen, setIsRecModalOpen] = useState(false);
  const [editingPet, setEditingPet] = useState<Pet | null>(null);
  const [selectedType, setSelectedType] = useState<FilterType>("All");
  const [recommendedPetIds, setRecommendedPetIds] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [sortBy, setSortBy] = useState<SortOption>("Newest");
  const [viewMode, setViewMode] = useState<ViewMode>("grid");
  const [darkMode, setDarkMode] = useState(false);
  const [posterPet, setPosterPet] = useState<Pet | null>(null);
  const [toasts, setToasts] = useState<Toast[]>([]);
  const [quoteIndex, setQuoteIndex] = useState(0);

  // Rotating quote logic
  useEffect(() => {
    const interval = setInterval(() => {
      setQuoteIndex((prev) => (prev + 1) % EMOTIONAL_QUOTES.length);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  // Prevent background scrolling when modals are open
  useEffect(() => {
    if (isModalOpen || isRecModalOpen || posterPet) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "unset";
    }
  }, [isModalOpen, isRecModalOpen, posterPet]);

  useEffect(() => {
    const savedPets = localStorage.getItem("streetpaws_local_pets");
    if (savedPets) {
      try {
        const parsed = JSON.parse(savedPets);
        setPets(parsed.map((p: any) => ({...normalizePet(p), postedAt: new Date(p.postedAt)})));
      } catch (e) {
        console.error("Failed to load local pets", e);
      }
    }
  }, []);

  const savePetsLocally = (newPets: Pet[]) => {
    localStorage.setItem("streetpaws_local_pets", JSON.stringify(newPets));
  };

  const addToast = (message: string, type: Toast["type"] = "info") => {
    const id = Math.random().toString(36);
    setToasts((prev) => [...prev, { id, message, type }]);
    setTimeout(() => setToasts((prev) => prev.filter((t) => t.id !== id)), 3000);
  };

  const [favorites, setFavorites] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem("streetpaws_favorites");
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const toggleFavorite = (petId: string) => {
    setFavorites((prev) => {
      const newFavs = prev.includes(petId) ? prev.filter(id => id !== petId) : [...prev, petId];
      localStorage.setItem("streetpaws_favorites", JSON.stringify(newFavs));
      return newFavs;
    });
    addToast(favorites.includes(petId) ? "Removed from favorites" : "Added to favorites", "success");
  };

  const handleAddComment = (petId: string, text: string) => {
    const newComment: Comment = { id: Math.random().toString(36), text, author: 'Community Member', createdAt: new Date() };
    const updatedPets = pets.map(p => p.id === petId ? { ...p, comments: [...p.comments, newComment] } : p);
    setPets(updatedPets);
    savePetsLocally(updatedPets);
    addToast("Note added!", "success");
  };

  const handleCheer = (petId: string) => {
    const updatedPets = pets.map(p => p.id === petId ? { ...p, cheers: p.cheers + 1 } : p);
    setPets(updatedPets);
    savePetsLocally(updatedPets);
  };

  const handleStatusChange = (petId: string, status: PetStatus) => {
     const updatedPets = pets.map(p => p.id === petId ? { ...p, status } : p);
     setPets(updatedPets);
     savePetsLocally(updatedPets);
     addToast(`Status updated to ${status}`, "success");
  };

  const handleSavePet = async (petData: Pet) => {
    const updatedPets = editingPet ? pets.map(p => p.id === petData.id ? petData : p) : [petData, ...pets];
    setPets(updatedPets);
    savePetsLocally(updatedPets);
    addToast(editingPet ? 'Listing updated!' : 'Pet listed successfully!', 'success');
    setIsModalOpen(false);
    setEditingPet(null);
  };

  const openEditPetModal = (pet: Pet) => {
    setEditingPet(pet);
    setIsModalOpen(true);
  };

  const filteredPets = pets.filter((pet) => {
    if (selectedType === "Recommended") return recommendedPetIds.includes(pet.id);
    const matchesType = selectedType === "All" || (selectedType === "Favorites" && favorites.includes(pet.id)) || (selectedType === "Urgent" && (pet.urgency === "High" || pet.urgency === "Critical")) || pet.type === selectedType;
    return matchesType && (pet.name.toLowerCase().includes(searchTerm.toLowerCase()) || pet.location.toLowerCase().includes(searchTerm.toLowerCase()));
  });

  const sortedPets = [...filteredPets].sort((a, b) => {
    if (a.status === "Adopted" && b.status !== "Adopted") return 1;
    if (b.status === "Adopted" && a.status !== "Adopted") return -1;
    if (sortBy === "Newest") return b.postedAt.getTime() - a.postedAt.getTime();
    if (sortBy === "Urgency") return urgencyScore(b.urgency) - urgencyScore(a.urgency);
    if (sortBy === "Name") return a.name.localeCompare(b.name);
    return 0;
  });

  return (
    <div className={`min-h-screen font-sans transition-colors duration-300 ${darkMode ? "bg-stone-900 text-stone-100" : "bg-stone-50 text-stone-800"}`}>

      {/* Toast Overlay */}
      <div className="fixed top-20 right-4 z-[100] space-y-2 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className={`pointer-events-auto px-4 py-3 rounded-2xl shadow-xl flex items-center gap-2 animate-in slide-in-from-right-10 ${toast.type === "success" ? "bg-green-600 text-white" : "bg-stone-800 text-white"}`}>
            {toast.type === "success" && <CheckCircle2 size={16} />}
            <span className="text-sm font-semibold">{toast.message}</span>
          </div>
        ))}
      </div>

      {/* Header */}
      <header className={`border-b shadow-sm transition-colors sticky top-0 z-40 px-4 h-16 flex items-center justify-between ${darkMode ? "bg-stone-900 border-stone-800" : "bg-white border-stone-200"}`}>
        <button onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})} className="flex items-center gap-2">
          <div className="w-8 h-8 sm:w-10 h-10 bg-amber-500 rounded-full flex items-center justify-center text-white">
            <PawPrint size={18} className="sm:size-[22px]" />
          </div>
          <h1 className="text-lg sm:text-xl font-black tracking-tight">
            Street<span className="text-amber-500">Paws</span>
          </h1>
        </button>

        <div className="flex items-center gap-2 sm:gap-4">
          <button onClick={() => setDarkMode(!darkMode)} className={`p-2 rounded-full transition-colors ${darkMode ? "bg-stone-800 text-amber-400" : "bg-stone-100 text-stone-600"}`}>
            {darkMode ? <Sun size={18} /> : <Moon size={18} />}
          </button>
          <button onClick={() => {setEditingPet(null); setIsModalOpen(true);}} className="bg-amber-600 text-white px-3 sm:px-5 py-2 rounded-full font-bold text-xs sm:text-sm hover:bg-amber-700 transition-all flex items-center gap-2 shadow-lg active:scale-95">
            <Plus size={16} />
            <span className="hidden xs:inline">List Stray</span>
          </button>
        </div>
      </header>

      {/* Hero Section */}
      <section className={`py-12 sm:py-20 px-4 text-center relative overflow-hidden transition-colors ${darkMode ? "bg-stone-800/50" : "bg-amber-50"}`}>
        <div className="max-w-4xl mx-auto relative z-10 space-y-4 sm:space-y-6">
          <div className="h-24 sm:h-32 flex items-center justify-center">
             <h2 key={quoteIndex} className="text-3xl sm:text-5xl md:text-6xl font-black leading-tight animate-in fade-in slide-in-from-bottom-4 duration-1000">
               {EMOTIONAL_QUOTES[quoteIndex].split(' ').map((word, i) => (
                 <span key={i} className={i % 3 === 2 ? "text-amber-500" : ""}>{word} </span>
               ))}
             </h2>
          </div>
          <p className="text-base sm:text-xl opacity-70 max-w-2xl mx-auto">
            Find, share, and protect the strays in your community. Every listing saves a life.
          </p>
          <div className="pt-2">
            <button onClick={() => setIsRecModalOpen(true)} className="bg-stone-900 dark:bg-amber-500 text-white dark:text-stone-900 px-8 py-4 rounded-2xl font-black text-sm sm:text-base shadow-2xl flex items-center gap-2 mx-auto hover:scale-105 transition-all active:scale-95">
              <Sparkles size={20} /> Match Me with a Pet
            </button>
          </div>
        </div>
      </section>

      <main className="max-w-7xl mx-auto px-4 py-6 sm:py-10">
        <div className="flex flex-col gap-4 mb-8">
          <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar scroll-smooth">
            {["All", "Favorites", "Urgent", "Recommended", "Dog", "Cat", "Bird", "Other"].map((type) => (
              <button
                key={type}
                onClick={() => { setSelectedType(type as FilterType); if (type !== 'Recommended') setRecommendedPetIds([]); }}
                className={`px-4 py-2.5 rounded-full text-xs sm:text-sm font-bold whitespace-nowrap transition-all border shrink-0 flex items-center gap-2 ${selectedType === type ? "bg-amber-500 text-white border-amber-500 shadow-lg shadow-amber-500/20" : darkMode ? "bg-stone-800 border-stone-700 text-stone-400" : "bg-white border-stone-200 text-stone-600"}`}
              >
                {type === "Favorites" && <Heart size={14} className={selectedType === "Favorites" ? "fill-white" : ""} />}
                {type}
              </button>
            ))}
          </div>

          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
              <input
                type="text"
                placeholder="Search location..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className={`w-full pl-12 pr-4 py-3.5 rounded-2xl border transition-all text-sm outline-none focus:ring-2 focus:ring-amber-500/30 ${darkMode ? "bg-stone-800 border-stone-600 text-white" : "bg-white border-stone-200"}`}
              />
            </div>
            <div className="flex gap-2">
              <select
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value as SortOption)}
                className={`flex-1 sm:w-40 px-4 py-3.5 rounded-2xl border font-bold text-sm outline-none transition-all ${darkMode ? "bg-stone-800 border-stone-600" : "bg-white border-stone-200"}`}
              >
                <option value="Newest">Recent</option>
                <option value="Urgency">Urgency</option>
                <option value="Name">Name</option>
              </select>
              <div className={`hidden xs:flex p-1 rounded-2xl border ${darkMode ? "bg-stone-800 border-stone-600" : "bg-white border-stone-200"}`}>
                <button onClick={() => setViewMode("grid")} className={`p-2 rounded-xl ${viewMode === "grid" ? (darkMode ? "bg-stone-700" : "bg-stone-100") : "opacity-40"}`}><Grid size={20} /></button>
                <button onClick={() => setViewMode("list")} className={`p-2 rounded-xl ${viewMode === "list" ? (darkMode ? "bg-stone-700" : "bg-stone-100") : "opacity-40"}`}><List size={20} /></button>
              </div>
            </div>
          </div>
        </div>

        <div className={`grid gap-4 sm:gap-6 ${viewMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1'}`}>
          {sortedPets.map((pet) => (
            <PetCard
              key={pet.id}
              pet={pet}
              darkMode={darkMode}
              viewMode={viewMode}
              isFavorite={favorites.includes(pet.id)}
              onToggleFavorite={() => toggleFavorite(pet.id)}
              onGeneratePoster={() => setPosterPet(pet)}
              onAddComment={handleAddComment}
              onCheer={handleCheer}
              onStatusChange={handleStatusChange}
              onEdit={() => openEditPetModal(pet)}
              onDelete={() => { if(confirm("Delete this listing?")) { const updated = pets.filter(p => p.id !== pet.id); setPets(updated); savePetsLocally(updated); addToast("Listing deleted", "info"); }}}
            />
          ))}
        </div>

        {sortedPets.length === 0 && (
            <div className={`py-20 text-center rounded-[2.5rem] border-2 border-dashed ${darkMode ? "border-stone-800 text-stone-600" : "border-stone-200 text-stone-400"}`}>
              <div className="mb-4 flex justify-center"><ImageIcon size={48} className="opacity-20" /></div>
              <p className="text-lg font-bold">No friends found.</p>
            </div>
        )}
      </main>

      {/* Floating Action Button for Mobile */}
      <button onClick={() => {setEditingPet(null); setIsModalOpen(true);}} className="sm:hidden fixed bottom-6 right-6 w-14 h-14 bg-amber-600 text-white rounded-full shadow-2xl flex items-center justify-center z-40 active:scale-90 transition-transform">
        <Plus size={24} />
      </button>

      {isModalOpen && (
        <PetFormModal
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          onSubmit={handleSavePet}
          darkMode={darkMode}
          initialData={editingPet || undefined}
        />
      )}

      {posterPet && <PosterModal pet={posterPet} onClose={() => setPosterPet(null)} darkMode={darkMode} />}

      {isRecModalOpen && (
        <RecommendationModal
          isOpen={isRecModalOpen}
          onClose={() => setIsRecModalOpen(false)}
          pets={pets}
          onRecommend={(ids) => {
            setRecommendedPetIds(ids);
            setSelectedType("Recommended");
            setIsRecModalOpen(false);
          }}
          darkMode={darkMode}
        />
      )}

      <footer className={`mt-10 py-10 border-t ${darkMode ? "border-stone-800" : "border-stone-200"}`}>
        <div className="max-w-7xl mx-auto px-4 flex flex-col items-center gap-4 text-center">
          <div className="flex items-center gap-2 font-black text-amber-500">
            <PawPrint size={20} /> StreetPaws Community
          </div>
          <p className="text-sm opacity-60 max-w-sm">Every stray animal listed here is looking for a human like you. Help us by sharing these listings.</p>
          <div className="space-y-2 mt-4">
            <p className="text-sm font-black text-stone-900 dark:text-stone-100">Developed by Gopal Patel</p>
            <p className="text-xs opacity-60">Interested in a custom professional website? Reach out at:</p>
            <a href="mailto:patelgopal563@gmail.com" className="text-amber-500 font-bold hover:underline">patelgopal563@gmail.com</a>
          </div>
        </div>
      </footer>
    </div>
  );
}

// --- Pet Listing Form Modal ---

function PetFormModal({ isOpen, onClose, onSubmit, darkMode, initialData }: { isOpen: boolean, onClose: () => void, onSubmit: (pet: Pet) => void, darkMode: boolean, initialData?: Pet }) {
  const [loadingBio, setLoadingBio] = useState(false);
  const [formData, setFormData] = useState({
    name: initialData?.name || "",
    type: initialData?.type || ("Dog" as PetType),
    age: initialData?.age || "",
    location: initialData?.location || "",
    description: initialData?.description || "",
    imageUrl: initialData?.imageUrl || "",
    contactNumber: initialData?.contactNumber || "",
    contactName: initialData?.contactName || "",
    urgency: initialData?.urgency || ("Medium" as UrgencyLevel),
    traits: initialData?.traits || "",
  });

  const generateBio = async () => {
    if (!formData.name || !formData.traits) return;
    setLoadingBio(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const res = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Create a professional, heartwarming 2-sentence adoption bio for a stray ${formData.type} named ${formData.name}. Traits: ${formData.traits}. Highlight empathy and community help.`
      });
      setFormData(prev => ({ ...prev, description: res.text?.trim() || "" }));
    } catch {
      alert("AI generator failed. Please write manually.");
    } finally { setLoadingBio(false); }
  };

  const inputStyles = `w-full p-4 rounded-2xl border font-medium text-base sm:text-sm transition-all outline-none focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 ${
    darkMode 
      ? "bg-stone-800 border-stone-600 text-white placeholder-stone-500" 
      : "bg-stone-50 border-stone-200 text-stone-800 placeholder-stone-400"
  }`;

  const labelStyles = `text-[11px] font-black uppercase tracking-widest mb-2 block px-1 ${
    darkMode ? "text-stone-300" : "text-stone-400"
  }`;

  return (
    <div className="fixed inset-0 z-[100] flex flex-col sm:items-center sm:justify-center bg-black/80 backdrop-blur-md overflow-hidden animate-in fade-in duration-300">
      <div className={`flex flex-col w-full h-full sm:h-auto sm:max-h-[90vh] sm:max-w-xl sm:rounded-[2.5rem] shadow-2xl animate-in zoom-in-95 slide-in-from-bottom-10 duration-500 ${darkMode ? "bg-stone-900" : "bg-white"}`}>

        <div className={`p-6 border-b flex justify-between items-center shrink-0 ${darkMode ? "border-stone-800 bg-stone-900 text-white" : "border-stone-100 bg-white"}`}>
          <div>
             <h2 className="text-xl sm:text-2xl font-black">{initialData ? "Edit Pet Details" : "Create New Listing"}</h2>
             <div className="flex items-center gap-1 text-[10px] font-bold uppercase tracking-widest text-amber-500">
                <Sparkles size={10} /> StreetPaws Verified
             </div>
          </div>
          <button onClick={onClose} className={`p-3 rounded-full hover:scale-110 active:scale-90 transition-transform ${darkMode ? "bg-stone-800 text-white" : "bg-stone-100 text-stone-900"}`}>
            <X size={20} />
          </button>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); onSubmit({ ...normalizePet(initialData || {}), ...formData, postedAt: initialData?.postedAt || new Date() }); }} className="flex-1 overflow-y-auto p-6 space-y-8 no-scrollbar scrollbar-hide pb-24">
          <div className="space-y-6">
            <section>
              <h3 className="text-sm font-black mb-4 flex items-center gap-2 text-blue-500"><User size={16}/> Identity</h3>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className={labelStyles}>Pet Name *</label>
                  <input required className={inputStyles} placeholder="Buddy, Fluffy..." value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
                <div>
                  <label className={labelStyles}>Animal Type *</label>
                  <select className={inputStyles} value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})}>
                    <option>Dog</option>
                    <option>Cat</option>
                    <option>Bird</option>
                    <option>Rat</option>
                    <option>Other</option>
                  </select>
                </div>
              </div>
            </section>

            <section>
              <h3 className="text-sm font-black mb-4 flex items-center gap-2 text-red-500"><ImageIcon size={16}/> Visuals</h3>
              <div className="space-y-3">
                <label className={labelStyles}>Live Image URL *</label>
                <input required className={inputStyles} type="url" placeholder="https://..." value={formData.imageUrl} onChange={e => setFormData({...formData, imageUrl: e.target.value})} />
                {formData.imageUrl && (
                  <div className="relative aspect-video rounded-3xl overflow-hidden shadow-inner border border-stone-200 dark:border-stone-700 bg-stone-100 dark:bg-stone-800">
                    <img src={formData.imageUrl} alt="Pet Preview" className="w-full h-full object-cover" onError={(e) => (e.currentTarget.src = 'https://images.unsplash.com/photo-1543466835-00a7907e9de1?auto=format&fit=crop&q=80&w=800')} />
                    <div className="absolute top-2 right-2 bg-black/60 text-white text-[10px] px-2 py-1 rounded-full font-bold">PREVIEW</div>
                  </div>
                )}
              </div>
