const PosterModal: React.FC<{ pet: Pet; onClose: () => void; darkMode: boolean }> = ({ pet, onClose, darkMode }) => {
  const [downloading, setDownloading] = useState(false);
  const posterRef = useRef<HTMLDivElement>(null);

  const waLink = `https://wa.me/${pet.contactNumber}?text=${encodeURIComponent(
    `🚨 *ADOPTION ALERT* 🚨\n\nMeet *${pet.name.toUpperCase()}*, a beautiful ${pet.type} found at ${pet.location}.\n\n*"${pet.description}"*\n\nHelp us find ${pet.name} a safe home! Shared via StreetPaws.`
  )}`;

  const handlePrint = () => {
    window.print();
  };

  const handleDownload = async () => {
    if (!posterRef.current || downloading) return;
    setDownloading(true);
    try {
      // @ts-ignore (html2canvas is available from the script tag)
      const canvas = await html2canvas(posterRef.current, {
        useCORS: true,
        scale: 2,
        backgroundColor: "#ffffff",
        logging: false
      });
      const dataUrl = canvas.toDataURL("image/png");
      const link = document.createElement("a");
      link.download = `STREETPAWS_${pet.name.toUpperCase()}_POSTER.png`;
      link.href = dataUrl;
      link.click();
    } catch (e) {
      console.error("Download failed:", e);
      alert("Download failed. Please use 'Save / Print' instead.");
    } finally {
      setDownloading(false);
    }
  };

