                </div>
                <div className="space-y-6">
                    <h3 className="text-lg font-bold">What soul are you ready to help?</h3>
                    <div className="grid grid-cols-2 gap-3">
                        {['Dog', 'Cat', 'Bird', 'Any'].map(t => <button key={t} onClick={() => setAnswers({type: t as any})} className={`p-5 rounded-[2rem] border-2 font-black transition-all ${answers.type === t ? 'bg-amber-500 border-amber-500 text-white scale-105 shadow-xl shadow-amber-500/20' : 'border-stone-100 dark:border-stone-800 hover:border-amber-500/30'}`}>{t}</button>)}
                    </div>
                    <button onClick={handleFinish} className="w-full bg-stone-900 dark:bg-amber-500 text-white dark:text-stone-900 py-5 rounded-[2rem] font-black shadow-2xl active:scale-95 transition-all">Find My Companion</button>
