// --- Helpers ---
const normalizePet = (p: Partial<Pet>): Pet => ({
  id: p.id || Math.random().toString(36).substring(2, 9),
  name: p.name || "",
  type: p.type || "Other",
  age: p.age || "",
  location: p.location || "",
  distance: p.distance || 0,
  description: p.description || "",
  imageUrl: p.imageUrl || "",
  contactNumber: p.contactNumber || "",
  contactName: p.contactName || "Anonymous",
  postedAt: p.postedAt ? new Date(p.postedAt) : new Date(),
  urgency: p.urgency || "Medium",
  status: p.status || "Available",
  traits: p.traits || "",
  comments: p.comments || [],
  cheers: p.cheers || 0,
});

const urgencyScore = (u: UrgencyLevel) => {
  switch (u) {
    case "Critical": return 4;
    case "High": return 3;
    case "Medium": return 2;
    case "Low": return 1;
    default: return 0;
  }
};

// --- Main App Component ---

function App() {
  const [pets, setPets] = useState<Pet[]>(INITIAL_PETS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isRecModalOpen, setIsRecModalOpen] = useState(false);
  const [editingPet, setEditingPet] = useState<Pet | null>(null);
  const [selectedType, setSelectedType] = useState<FilterType>("All");
  const [recommendedPetIds, setRecommendedPetIds] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [sortBy, setSortBy] = useState<SortOption>("Newest");
  const [viewMode, setViewMode] = useState<ViewMode>("grid");
  const [darkMode, setDarkMode] = useState(false);
  const [posterPet, setPosterPet] = useState<Pet | null>(null);
  const [toasts, setToasts] = useState<Toast[]>([]);
  const [quoteIndex, setQuoteIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setQuoteIndex((prev) => (prev + 1) % EMOTIONAL_QUOTES.length);
    }, 4500);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (isModalOpen || isRecModalOpen || posterPet) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "unset";
    }
  }, [isModalOpen, isRecModalOpen, posterPet]);

  useEffect(() => {
    const savedPets = localStorage.getItem("streetpaws_local_pets");
    if (savedPets) {
      try {
        const parsed = JSON.parse(savedPets);
        setPets(parsed.map((p: any) => ({...normalizePet(p), postedAt: new Date(p.postedAt)})));
      } catch (e) {
        console.error("Failed to load local pets", e);
      }
    }
  }, []);

  const savePetsLocally = (newPets: Pet[]) => {
    localStorage.setItem("streetpaws_local_pets", JSON.stringify(newPets));
  };

  const addToast = (message: string, type: Toast["type"] = "info") => {
    const id = Math.random().toString(36);
    setToasts((prev) => [...prev, { id, message, type }]);
    setTimeout(() => setToasts((prev) => prev.filter((t) => t.id !== id)), 3000);
  };

  const [favorites, setFavorites] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem("streetpaws_favorites");
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const toggleFavorite = (petId: string) => {
    setFavorites((prev) => {
      const isFav = prev.includes(petId);
      const newFavs = isFav ? prev.filter(id => id !== petId) : [...prev, petId];
      localStorage.setItem("streetpaws_favorites", JSON.stringify(newFavs));
      addToast(isFav ? "Removed from favorites" : "Added to favorites", "success");
      return newFavs;
    });
  };

  const handleAddComment = (petId: string, text: string) => {
    const newComment: Comment = { 
      id: Math.random().toString(36), 
      text, 
      author: 'Community Member', 
      createdAt: new Date() 
    };
    const updatedPets = pets.map(p => p.id === petId ? { ...p, comments: [...p.comments, newComment] } : p);
    setPets(updatedPets);
    savePetsLocally(updatedPets);
    addToast("Note added!", "success");
  };

  const handleCheer = (petId: string) => {
    const updatedPets = pets.map(p => p.id === petId ? { ...p, cheers: p.cheers + 1 } : p);
    setPets(updatedPets);
    savePetsLocally(updatedPets);
  };

  const handleStatusChange = (petId: string, status: PetStatus) => {
     const updatedPets = pets.map(p => p.id === petId ? { ...p, status } : p);
     setPets(updatedPets);
     savePetsLocally(updatedPets);
     addToast(`Status updated to ${status}`, "success");
  };

  const handleDeletePet = (petId: string) => {
    if (confirm("Permanently delete this listing?")) {
      const updatedPets = pets.filter(p => p.id !== petId);
      setPets(updatedPets);
      savePetsLocally(updatedPets);
      addToast("Listing deleted.", "info");
    }
  };

  const handleSavePet = async (petData: Pet) => {
    const updatedPets = editingPet 
      ? pets.map(p => p.id === petData.id ? petData : p) 
      : [petData, ...pets];
    setPets(updatedPets);
    savePetsLocally(updatedPets);
    addToast(editingPet ? 'Details updated!' : 'Pet listed!', 'success');
    setIsModalOpen(false);
    setEditingPet(null);
  };

  const filteredPets = pets.filter((pet) => {
    if (selectedType === "Recommended") return recommendedPetIds.includes(pet.id);
    const matchesType = selectedType === "All" || (selectedType === "Favorites" && favorites.includes(pet.id)) || (selectedType === "Urgent" && (pet.urgency === "High" || pet.urgency === "Critical")) || pet.type === selectedType;
    return matchesType && (pet.name.toLowerCase().includes(searchTerm.toLowerCase()) || pet.location.toLowerCase().includes(searchTerm.toLowerCase()));
  });

  const sortedPets = [...filteredPets].sort((a, b) => {
    if (a.status === "Adopted" && b.status !== "Adopted") return 1;
    if (b.status === "Adopted" && a.status !== "Adopted") return -1;
    if (sortBy === "Newest") return b.postedAt.getTime() - a.postedAt.getTime();
    if (sortBy === "Urgency") return urgencyScore(b.urgency) - urgencyScore(a.urgency);
    if (sortBy === "Name") return a.name.localeCompare(b.name);
    return 0;
  });

  return (
    <div className={`min-h-screen font-sans transition-colors duration-300 ${darkMode ? "bg-stone-900 text-stone-100" : "bg-stone-50 text-stone-800"}`}>

      {/* Toasts */}
      <div className="fixed top-20 right-4 z-[100] space-y-2 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className={`pointer-events-auto px-4 py-3 rounded-2xl shadow-xl flex items-center gap-2 animate-in slide-in-from-right-10 ${toast.type === "success" ? "bg-green-600 text-white" : "bg-stone-800 text-white"}`}>
            {toast.type === "success" && <CheckCircle2 size={16} />}
            <span className="text-sm font-semibold">{toast.message}</span>
          </div>
        ))}
      </div>

      {/* Navigation */}
      <header className={`border-b shadow-sm transition-colors sticky top-0 z-40 px-4 h-16 flex items-center justify-between ${darkMode ? "bg-stone-900 border-stone-800" : "bg-white border-stone-200"}`}>
        <button onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})} className="flex items-center gap-2 group">
          <div className="w-10 h-10 bg-amber-500 rounded-full flex items-center justify-center text-white transition-transform group-hover:scale-110">
            <PawPrint size={22} />
          </div>
          <h1 className="text-xl font-black tracking-tight">
            Street<span className="text-amber-500">Paws</span>
          </h1>
        </button>

        <div className="flex items-center gap-2 sm:gap-4">
          <button onClick={() => setDarkMode(!darkMode)} className={`p-2 rounded-full transition-colors ${darkMode ? "bg-stone-800 text-amber-400" : "bg-stone-100 text-stone-600"}`}>
            {darkMode ? <Sun size={20} /> : <Moon size={20} />}
          </button>
          <button onClick={() => {setEditingPet(null); setIsModalOpen(true);}} className="bg-amber-600 text-white px-5 py-2.5 rounded-full font-bold text-sm hover:bg-amber-700 transition-all flex items-center gap-2 shadow-lg active:scale-95">
            <Plus size={18} />
            <span className="hidden xs:inline">List stray</span>
          </button>
        </div>
      </header>

      {/* Hero */}
      <section className={`py-12 sm:py-20 px-4 text-center relative overflow-hidden transition-colors ${darkMode ? "bg-stone-800/30" : "bg-amber-50"}`}>
        <div className="max-w-4xl mx-auto relative z-10 space-y-6">
          <div className="h-24 sm:h-32 flex items-center justify-center">
             <h2 key={quoteIndex} className="text-3xl sm:text-5xl md:text-6xl font-black leading-tight animate-in fade-in slide-in-from-bottom-4 duration-700">
               {EMOTIONAL_QUOTES[quoteIndex].split(' ').map((word, i) => (
                 <span key={i} className={i % 3 === 1 ? "text-amber-500" : ""}>{word} </span>
               ))}
             </h2>
          </div>
          <p className="text-base sm:text-xl opacity-70 max-w-2xl mx-auto italic font-medium">
            "Every paw has a story waiting for a happy ending."
          </p>
          <button onClick={() => setIsRecModalOpen(true)} className="bg-stone-900 dark:bg-amber-500 text-white dark:text-stone-900 px-8 py-4 rounded-3xl font-black text-sm sm:text-base shadow-2xl flex items-center gap-2 mx-auto hover:scale-105 transition-all active:scale-95 group">
            <Sparkles size={20} className="group-hover:animate-pulse" /> Find a companion
          </button>
        </div>
      </section>

      {/* Main Grid */}
      <main className="max-w-7xl mx-auto px-4 py-8">
        <div className="flex flex-col gap-6 mb-10">
          <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar scroll-smooth">
            {["All", "Favorites", "Urgent", "Recommended", "Dog", "Cat", "Bird", "Other"].map((type) => (
              <button
                key={type}
                onClick={() => { setSelectedType(type as FilterType); if (type !== 'Recommended') setRecommendedPetIds([]); }}
                className={`px-5 py-2.5 rounded-full text-xs sm:text-sm font-bold whitespace-nowrap transition-all border shrink-0 flex items-center gap-2 ${selectedType === type ? "bg-amber-500 text-white border-amber-500 shadow-lg shadow-amber-500/20" : darkMode ? "bg-stone-800 border-stone-700 text-stone-400" : "bg-white border-stone-200 text-stone-600 hover:border-amber-500/50"}`}
              >
                {type === "Favorites" && <Heart size={14} className={selectedType === "Favorites" ? "fill-white" : ""} />}
                {type}
              </button>
            ))}
          </div>

          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
              <input
                type="text"
                placeholder="Search area or animal name..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className={`w-full pl-12 pr-4 py-4 rounded-3xl border transition-all text-sm outline-none focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 ${darkMode ? "bg-stone-800 border-stone-600 text-white placeholder-stone-500" : "bg-white border-stone-200"}`}
              />
            </div>
            <div className="flex gap-2">
              <select
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value as SortOption)}
                className={`flex-1 sm:w-44 px-5 py-4 rounded-3xl border font-bold text-sm outline-none transition-all cursor-pointer ${darkMode ? "bg-stone-800 border-stone-600 text-white" : "bg-white border-stone-200"}`}
              >
                <option value="Newest">Recent First</option>
                <option value="Urgency">Urgency High</option>
                <option value="Name">Name A-Z</option>
              </select>
              <div className={`hidden xs:flex p-1 rounded-3xl border ${darkMode ? "bg-stone-800 border-stone-600" : "bg-white border-stone-200"}`}>
                <button onClick={() => setViewMode("grid")} className={`p-3 rounded-2xl ${viewMode === "grid" ? (darkMode ? "bg-stone-700 text-amber-500" : "bg-stone-100 text-amber-600") : "opacity-40"}`}><Grid size={20} /></button>
                <button onClick={() => setViewMode("list")} className={`p-3 rounded-2xl ${viewMode === "list" ? (darkMode ? "bg-stone-700 text-amber-500" : "bg-stone-100 text-amber-600") : "opacity-40"}`}><List size={20} /></button>
              </div>
            </div>
          </div>
        </div>

        <div className={`grid gap-6 ${viewMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1'}`}>
          {sortedPets.map((pet) => (
            <PetCard
              key={pet.id}
              pet={pet}
              darkMode={darkMode}
              viewMode={viewMode}
              isFavorite={favorites.includes(pet.id)}
              onToggleFavorite={() => toggleFavorite(pet.id)}
              onGeneratePoster={() => setPosterPet(pet)}
              onAddComment={handleAddComment}
              onCheer={handleCheer}
              onStatusChange={handleStatusChange}
              onEdit={() => { setEditingPet(pet); setIsModalOpen(true); }}
              onDelete={() => handleDeletePet(pet.id)}
            />
          ))}
        </div>

        {sortedPets.length === 0 && (
            <div className={`py-32 text-center rounded-[3rem] border-4 border-dashed animate-in fade-in duration-500 ${darkMode ? "border-stone-800 text-stone-600" : "border-stone-200 text-stone-400"}`}>
              <div className="mb-6 flex justify-center"><ImageIcon size={64} className="opacity-20" /></div>
              <p className="text-xl font-black">No strays found in this view.</p>
              <p className="text-sm opacity-60 mt-2">Help the community by listing strays you encounter.</p>
            </div>
        )}
      </main>

      {/* Footer */}
      <footer className={`mt-20 py-16 border-t transition-colors ${darkMode ? "border-stone-800 bg-stone-900/50" : "border-stone-200 bg-white"}`}>
        <div className="max-w-7xl mx-auto px-4 flex flex-col items-center gap-8 text-center">
          <div className="flex items-center gap-2 font-black text-amber-500 text-2xl">
            <PawPrint size={28} /> StreetPaws
          </div>
          <p className="text-base opacity-60 max-w-lg leading-relaxed font-medium">
            Bridging the gap between the streets and a loving home. We believe every soul deserves safety and a warm bed.
          </p>
          <div className="p-8 rounded-[2.5rem] border border-amber-500/30 bg-amber-500/5 max-w-md w-full shadow-inner">
            <p className="text-xs font-black text-amber-600 uppercase tracking-[0.3em] mb-3">Project Credits</p>
            <p className="text-lg font-black text-stone-900 dark:text-stone-100">Developed by Gopal Patel</p>
            <p className="text-xs opacity-60 mb-6 font-medium">"Creating digital experiences with heart."</p>
            <div className="space-y-3">
              <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest block">Available for Hire</span>
              <a href="mailto:patelgopal563@gmail.com" className="inline-block bg-amber-500 text-stone-900 px-6 py-3 rounded-2xl text-sm font-black hover:bg-amber-600 transition-all active:scale-95 shadow-lg">patelgopal563@gmail.com</a>
            </div>
          </div>
          <div className="text-[10px] font-bold opacity-30 uppercase tracking-[0.4em]">© 2025 StreetPaws Community</div>
        </div>
      </footer>

      {/* Modals */}
      {isModalOpen && (
        <PetFormModal
          isOpen={isModalOpen}
          onClose={() => { setIsModalOpen(false); setEditingPet(null); }}
          onSubmit={handleSavePet}
          darkMode={darkMode}
          initialData={editingPet || undefined}
        />
      )}

      {posterPet && (
        <PosterModal 
          pet={posterPet} 
          onClose={() => setPosterPet(null)} 
          darkMode={darkMode} 
        />
      )}

      {isRecModalOpen && (
        <RecommendationModal
          isOpen={isRecModalOpen}
          onClose={() => setIsRecModalOpen(false)}
          pets={pets}
          onRecommend={(ids) => {
            setRecommendedPetIds(ids);
            setSelectedType("Recommended");
            setIsRecModalOpen(false);
          }}
          darkMode={darkMode}
        />
      )}
    </div>
  );
}

