  );
}

// --- Poster Modal ---

const PosterModal: React.FC<{ pet: Pet; onClose: () => void; darkMode: boolean }> = ({ pet, onClose, darkMode }) => {
  const [downloading, setDownloading] = useState(false);
  const posterRef = useRef<HTMLDivElement>(null);

  const waLink = `https://wa.me/${pet.contactNumber}?text=${encodeURIComponent(
    `🚨 *ADOPTION NEEDED* 🚨\n\nMeet *${pet.name.toUpperCase()}*, a ${pet.type} found at ${pet.location}.\n\n*"${pet.description}"*\n\nHelp us find ${pet.name} a safe home. Shared via StreetPaws.`
  )}`;

  const handlePrint = () => window.print();

  const handleDownload = async () => {
    if (!posterRef.current || downloading) return;
    setDownloading(true);
    try {
      // Create a clean off-screen capture area to avoid UI glitches
      const clone = posterRef.current.cloneNode(true) as HTMLDivElement;
      clone.style.width = "500px";
      clone.style.position = "absolute";
      clone.style.top = "-9999px";
      clone.style.left = "-9999px";
      clone.style.minHeight = "707px"; // A4 Ratio
      clone.classList.remove('shadow-lg');
      document.body.appendChild(clone);

      // @ts-ignore
      const canvas = await html2canvas(clone, {
        useCORS: true,
        scale: 3,
        backgroundColor: "#ffffff",
        logging: false
      });

      document.body.removeChild(clone);

      const dataUrl = canvas.toDataURL("image/png");
      const link = document.createElement("a");
      link.download = `POSTER_${pet.name.toUpperCase()}.png`;
      link.href = dataUrl;
      link.click();
    } catch (e) {
      console.error(e);
      alert("Poster download failed. Use 'PDF Print' instead.");
    } finally {
      setDownloading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex flex-col sm:items-center sm:justify-center bg-black/95 backdrop-blur-xl animate-in fade-in duration-300 overflow-hidden">

      <div className={`flex flex-col w-full h-full sm:h-auto sm:max-h-[95vh] sm:max-w-2xl overflow-hidden animate-in zoom-in-95 duration-500 ${darkMode ? "bg-stone-900" : "bg-white"} sm:rounded-[3rem] shadow-2xl`}>

        {/* Header Controls */}
        <div className={`p-4 sm:p-6 border-b flex justify-between items-center sticky top-0 z-20 no-print ${darkMode ? "bg-stone-900 border-stone-800 text-white" : "bg-white border-stone-100 text-stone-900"}`}>
            <div>
              <h3 className="font-black text-xl leading-none">High-Impact Poster</h3>
              <p className="text-[10px] uppercase font-black tracking-widest opacity-40 mt-1">Ready for print & share</p>
            </div>
            <div className="flex items-center gap-2">
                <button onClick={handleDownload} disabled={downloading} className="bg-amber-500 text-stone-900 p-3 sm:px-5 sm:py-3 rounded-2xl flex items-center gap-2 font-black text-xs sm:text-sm active:scale-95 transition-all disabled:opacity-50">
                   <Download size={18}/> <span className="hidden xs:inline">{downloading ? "Saving..." : "Download"}</span>
                </button>
                <button onClick={handlePrint} className="bg-stone-900 dark:bg-stone-100 text-white dark:text-stone-900 p-3 sm:px-5 sm:py-3 rounded-2xl flex items-center gap-2 font-black text-xs sm:text-sm active:scale-95 transition-all">
                  <Printer size={18}/> <span className="hidden xs:inline">Print / PDF</span>
                </button>
                <button onClick={onClose} className={`p-3 rounded-full transition-all flex items-center justify-center ${darkMode ? "bg-stone-800 text-white hover:bg-stone-700" : "bg-stone-100 text-stone-900 hover:bg-stone-200"}`}>
                  <X size={24} />
                </button>
            </div>
        </div>

        {/* Poster Render Area */}
        <div className="flex-1 overflow-y-auto no-scrollbar scrollbar-hide bg-stone-100 p-4 sm:p-12 pb-24 sm:pb-12 flex flex-col items-center">
          <div 
            ref={posterRef}
            id="printable-poster" 
            className="bg-white border-[14px] sm:border-[28px] border-red-600 overflow-hidden flex flex-col items-center text-center w-full max-w-[500px] shadow-lg relative"
            style={{ aspectRatio: '1/1.414' }}
          >
              <div className="bg-red-600 text-white w-full py-8 sm:py-14 px-4 flex flex-col items-center">
                <h1 className="text-5xl sm:text-8xl font-black uppercase leading-none tracking-tighter italic italic-scale-y-110">ADOPT ME!</h1>
                <p className="text-[10px] sm:text-base font-black uppercase tracking-[0.3em] mt-3 opacity-95">Saving a life starts with you</p>
              </div>

              <div className="mt-12 sm:mt-16 relative px-10 w-full flex justify-center">
                  <div className="aspect-square bg-stone-900 rounded-[2.5rem] sm:rounded-[4rem] p-0.5 sm:p-1 shadow-2xl overflow-hidden w-full max-w-[380px]">
                    <img src={pet.imageUrl} className="w-full h-full object-cover rounded-[2.4rem] sm:rounded-[3.9rem]" alt={pet.name} crossOrigin="anonymous" />
                  </div>
