function RecommendationModal({ isOpen, onClose, pets, onRecommend, darkMode }: { isOpen: boolean, onClose: () => void, pets: Pet[], onRecommend: (ids: string[]) => void, darkMode: boolean }) {
    const [answers, setAnswers] = useState({ type: 'Any' });
    if (!isOpen) return null;
    const handleFinish = () => {
        const matches = pets.filter(p => answers.type === 'Any' || p.type === answers.type);
        onRecommend(matches.map(p => p.id));
    };
    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
            <div className={`p-8 rounded-[3rem] shadow-2xl w-full max-w-md border-4 border-white dark:border-stone-800 ${darkMode ? "bg-stone-900 text-white" : "bg-white text-stone-800"}`}>
                <div className="flex justify-between items-center mb-8">
                    <h2 className="text-2xl font-black flex items-center gap-2">Match Finder</h2>
                    <button onClick={onClose} className={`p-2 rounded-full flex items-center justify-center ${darkMode ? "text-white hover:bg-stone-800" : "text-stone-900 hover:bg-stone-100"}`}><X size={24} /></button>
                </div>
                <div className="space-y-8">
                    <h3 className="text-lg font-bold">What kind of animal are you ready to support?</h3>
                    <div className="grid grid-cols-2 gap-3">
                        {['Dog', 'Cat', 'Bird', 'Any'].map(t => <button key={t} onClick={() => setAnswers({type: t as any})} className={`p-6 rounded-[2.5rem] border-2 font-black transition-all ${answers.type === t ? 'bg-amber-500 border-amber-500 text-stone-900 scale-105 shadow-xl shadow-amber-500/20' : 'border-stone-100 dark:border-stone-800 hover:border-amber-500/30 text-stone-500'}`}>{t}</button>)}
                    </div>
                    <button onClick={handleFinish} className="w-full bg-stone-900 dark:bg-amber-500 text-white dark:text-stone-900 py-5 rounded-[2.5rem] font-black shadow-2xl active:scale-95 transition-all">Search matching souls</button>
                </div>
            </div>
        </div>
    );
}

