  Pencil,
  Trash2,
  Image as ImageIcon,
  User,
  Phone,
  Moon,
  Sun,
  Grid,
  List,
  Download,
  Share2,
} from "lucide-react";

// --- Types & Constants ---
type PetType = "Dog" | "Cat" | "Bird" | "Rat" | "Other";
type SortOption = "Newest" | "Oldest" | "Name" | "Urgency";
type FilterType = PetType | "All" | "Favorites" | "Urgent" | "Recommended";
type ViewMode = "grid" | "list";
type UrgencyLevel = "Low" | "Medium" | "High" | "Critical";
type PetStatus = "Available" | "Adopted" | "Fostered";

const EMOTIONAL_QUOTES = [
  "Every life matters.",
  "Be the voice for those who cannot speak.",
  "Love is a four-legged word.",
  "Saving one animal changes the world for them.",
  "Adoption is an act of pure love.",
  "Kindness starts with a big heart.",
  "Compassion is the heart of every home."
];

interface Comment {
  id: string;
  text: string;
  createdAt: Date;
  author: string;
}

interface Pet {
  id: string;
  name: string;
  type: PetType;
  age: string;
  location: string;
  distance: number;
  description: string;
  imageUrl: string;
  contactNumber: string;
  contactName: string;
  postedAt: Date;
  urgency: UrgencyLevel;
  status: PetStatus;
  traits: string;
  comments: Comment[];
  cheers: number;
}

interface Toast {
  id: string;
  message: string;
  type: "success" | "error" | "info";
}

