                         Chat With: {pet.contactName}
                      </p>
                  </div>
                  <div className="flex justify-center items-center gap-4 sm:gap-8 opacity-20 font-black uppercase tracking-[0.8em] text-[14px] sm:text-[20px]">
                      <PawPrint size={32} /> STREETPAWS
                  </div>
              </div>
          </div>
        </div>
      </div>
    </div>
  );
};

