const PosterModal: React.FC<{ pet: Pet; onClose: () => void; darkMode: boolean }> = ({ pet, onClose, darkMode }) => {
  const [downloading, setDownloading] = useState(false);
  const posterRef = useRef<HTMLDivElement>(null);

  const handleDownload = async () => {
    if (!posterRef.current || downloading) return;
    setDownloading(true);
    try {
      const clone = posterRef.current.cloneNode(true) as HTMLDivElement;
      clone.style.width = "500px";
      clone.style.position = "absolute";
      clone.style.top = "-9999px";
      clone.style.left = "-9999px";
      clone.style.minHeight = "707px";
      clone.classList.remove('shadow-lg');
      document.body.appendChild(clone);

      // @ts-ignore
      const canvas = await html2canvas(clone, {
        useCORS: true,
        scale: 3,
        backgroundColor: "#ffffff",
        logging: false
      });

      document.body.removeChild(clone);

      const dataUrl = canvas.toDataURL("image/png");
      const link = document.createElement("a");
      link.download = `POSTER_${pet.name.toUpperCase()}.png`;
      link.href = dataUrl;
      link.click();
    } catch (e) {
      console.error(e);
      alert("Capture failed. Use Print as PDF instead.");
    } finally {
      setDownloading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex flex-col sm:items-center sm:justify-center bg-black/95 backdrop-blur-xl animate-in fade-in duration-300 overflow-hidden">

      <div className={`flex flex-col w-full h-full sm:h-auto sm:max-h-[95vh] sm:max-w-2xl overflow-hidden animate-in zoom-in-95 duration-500 ${darkMode ? "bg-stone-900 text-stone-100" : "bg-white text-stone-900"} sm:rounded-[3rem] shadow-2xl`}>

