          >
              <div className="bg-red-600 text-white w-full py-10 sm:py-16 px-4 flex flex-col items-center">
                <h1 className="text-5xl sm:text-8xl font-black uppercase leading-none tracking-tighter italic scale-y-110">ADOPT ME!</h1>
