  "Compassion is the heart of every home."
];

interface Comment {
  id: string;
  text: string;
  createdAt: Date;
  author: string;
}

interface Pet {
  id: string;
  name: string;
  type: PetType;
  age: string;
  location: string;
  distance: number;
  description: string;
  imageUrl: string;
  contactNumber: string;
  contactName: string;
  postedAt: Date;
  urgency: UrgencyLevel;
  status: PetStatus;
  traits: string;
  comments: Comment[];
  cheers: number;
}

interface Toast {
  id: string;
  message: string;
  type: "success" | "error" | "info";
}

