      {posterPet && (
        <PosterModal 
          pet={posterPet} 
          onClose={() => setPosterPet(null)} 
          darkMode={darkMode} 
        />
      )}

      {isRecModalOpen && (
        <RecommendationModal
          isOpen={isRecModalOpen}
          onClose={() => setIsRecModalOpen(false)}
          pets={pets}
          onRecommend={(ids) => {
            setRecommendedPetIds(ids);
            setSelectedType("Recommended");
            setIsRecModalOpen(false);
          }}
          darkMode={darkMode}
        />
      )}
    </div>
  );
}

