                         Reporter: {pet.contactName}
                      </p>
                  </div>
                  <div className="flex justify-center items-center gap-4 opacity-10 font-black uppercase tracking-[0.8em] text-[12px] sm:text-[16px]">
                      <PawPrint size={24} /> STREETPAWS
