const PosterModal: React.FC<{ pet: Pet; onClose: () => void; darkMode: boolean }> = ({ pet, onClose, darkMode }) => {
  const [downloading, setDownloading] = useState(false);
  const posterRef = useRef<HTMLDivElement>(null);

  const handleDownload = async () => {
    if (!posterRef.current || downloading) return;
    setDownloading(true);
    try {
      // Temporarily clone the poster and make sure it has full height for capture
      const original = posterRef.current;
      const clone = original.cloneNode(true) as HTMLDivElement;

      // Set width to a higher fixed resolution for sharp export
      clone.style.width = "800px";
      clone.style.height = "auto";
      clone.style.position = "absolute";
      clone.style.top = "-9999px";
      clone.style.left = "-9999px";
      clone.style.boxShadow = "none";
      clone.style.transform = "none";
      clone.style.borderWidth = "30px"; // Thicker border for high-res

      document.body.appendChild(clone);

      // Wait a tiny bit for the clone to "settle" and images to load
      await new Promise(r => setTimeout(r, 200));

      // Use html2canvas to capture the CLONE which has auto height
      // @ts-ignore
      const canvas = await html2canvas(clone, {
        useCORS: true,
        scale: 2,
        backgroundColor: "#ffffff",
        logging: false,
        width: 800,
        height: clone.scrollHeight, // Capture full scrollable height
      });

      document.body.removeChild(clone);

      const dataUrl = canvas.toDataURL("image/png");
      const link = document.createElement("a");
      link.download = `STREETPAWS_POSTER_${pet.name.toUpperCase()}.png`;
      link.href = dataUrl;
      link.click();
    } catch (e) {
      console.error(e);
      alert("Capture failed. Please try the Print PDF option instead.");
    } finally {
      setDownloading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex flex-col sm:items-center sm:justify-center bg-black/95 backdrop-blur-xl animate-in fade-in duration-300 overflow-hidden">

      {/* Container for the modal content */}
      <div className={`flex flex-col w-full h-full sm:h-auto sm:max-h-[95vh] sm:max-w-2xl overflow-hidden animate-in zoom-in-95 duration-500 ${darkMode ? "bg-stone-900 text-stone-100" : "bg-white text-stone-900"} sm:rounded-[3rem] shadow-2xl`}>

        {/* Header Controls (Hidden on Print) */}
        <div className={`p-4 sm:p-6 border-b flex justify-between items-center sticky top-0 z-20 no-print ${darkMode ? "bg-stone-900 border-stone-800" : "bg-white border-stone-100"}`}>
            <div>
              <h3 className="font-black text-xl leading-none">Adopt Me Poster</h3>
              <p className="text-[10px] uppercase font-black tracking-widest opacity-40 mt-1 italic">Ready for High-Res Save</p>
            </div>
            <div className="flex items-center gap-2">
                <button onClick={handleDownload} disabled={downloading} className="bg-amber-500 text-stone-900 px-4 py-3 rounded-2xl flex items-center gap-2 font-black text-xs sm:text-sm active:scale-95 transition-all disabled:opacity-50">
                   <Download size={18}/> <span className="hidden xs:inline">{downloading ? "Preparing..." : "Save Image"}</span>
                </button>
                <button onClick={() => window.print()} className="bg-stone-900 dark:bg-stone-100 text-white dark:text-stone-900 px-4 py-3 rounded-2xl flex items-center gap-2 font-black text-xs sm:text-sm active:scale-95 transition-all">
                  <Printer size={18}/> <span className="hidden xs:inline">Print A4</span>
                </button>
                <button onClick={onClose} className={`p-3 rounded-full transition-all flex items-center justify-center ${darkMode ? "bg-stone-800 text-white hover:bg-stone-700" : "bg-stone-100 text-stone-900 hover:bg-stone-200"}`}>
                  <X size={24} />
                </button>
            </div>
        </div>

        {/* Poster Rendering Area - Scrollable for the Modal View */}
        <div className="flex-1 overflow-y-auto no-scrollbar bg-stone-100 p-4 sm:p-12 pb-24 sm:pb-12 flex flex-col items-center">

          {/* THE POSTER DIV - This is what gets captured/printed */}
          <div 
            ref={posterRef}
            id="printable-poster" 
            className="bg-white border-[16px] sm:border-[24px] border-red-600 overflow-visible flex flex-col items-center text-center w-full max-w-[500px] shadow-2xl relative"
            style={{ height: 'auto' }} // Ensure height is dynamic
          >
              <div className="bg-red-600 text-white w-full py-10 sm:py-16 px-4 flex flex-col items-center">
                <h1 className="text-5xl sm:text-7xl font-black uppercase leading-none tracking-tighter italic scale-y-110">ADOPT ME!</h1>
                <p className="text-[10px] sm:text-sm font-black uppercase tracking-[0.4em] mt-3 opacity-95">EVERY LIFE DESERVES A HOME</p>
              </div>

              <div className="mt-10 sm:mt-16 relative px-8 w-full flex justify-center">
                  <div className="aspect-square bg-stone-900 rounded-[2.5rem] sm:rounded-[3.5rem] p-0.5 sm:p-1 shadow-2xl overflow-hidden w-full max-w-[340px]">
                    <img src={pet.imageUrl} className="w-full h-full object-cover rounded-[2.4rem] sm:rounded-[3.4rem]" alt={pet.name} crossOrigin="anonymous" />
                  </div>
                  <div className="absolute -bottom-6 bg-amber-500 text-stone-900 px-8 sm:px-12 py-4 sm:py-6 rounded-3xl sm:rounded-4xl font-black text-xs sm:text-3xl rotate-2 shadow-2xl border-4 sm:border-8 border-white whitespace-nowrap">
                    I'M {pet.name.toUpperCase()}!
                  </div>
              </div>

              <div className="mt-16 sm:mt-24 px-10 sm:px-12 pb-8">
                 <h2 className="text-3xl sm:text-6xl font-black text-stone-900 mb-2 uppercase tracking-tight leading-none">{pet.name}</h2>
                 <p className="text-[10px] sm:text-base font-black uppercase tracking-widest text-stone-400 mb-8 sm:mb-12">{pet.type} • Spied at {pet.location}</p>
                 <div className="relative">
                    <p className="text-xl sm:text-2xl font-serif italic text-stone-800 leading-relaxed font-bold">
                       "{pet.description}"
                    </p>
