                  <div className="bg-stone-900 text-white py-6 sm:py-12 px-8 sm:px-14 rounded-[2.5rem] sm:rounded-[4rem] flex flex-col items-center shadow-2xl mb-8 sm:mb-16 w-full">
                      <p className="text-3xl sm:text-7xl font-black tracking-tighter leading-none">{pet.contactNumber}</p>
                      <p className="text-[12px] sm:text-lg font-bold opacity-60 mt-3 sm:mt-6 uppercase tracking-[0.2em] flex items-center gap-2">
                         Reporter: {pet.contactName}
                      </p>
                  </div>
                  <div className="flex justify-center items-center gap-4 opacity-10 font-black uppercase tracking-[0.8em] text-[12px] sm:text-[16px]">
                      <PawPrint size={24} /> STREETPAWS
                  </div>
              </div>
          </div>
        </div>
      </div>
    </div>
  );
