}

interface Pet {
  id: string;
  name: string;
  type: PetType;
  age: string;
  location: string;
  distance: number;
  description: string;
  imageUrl: string;
  contactNumber: string;
  contactName: string;
  postedAt: Date;
  urgency: UrgencyLevel;
  status: PetStatus;
  traits: string;
