                  </div>
               </div>
            </section>

            <section>
              <h3 className="text-[11px] font-black mb-4 flex items-center gap-2 text-green-500 uppercase tracking-widest"><Phone size={14}/> Contact Details</h3>
              <div className="space-y-4">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div>
                    <label className={labelStyles}>Location Description *</label>
