                  </div>
                  <p className="text-[8px] sm:text-xs font-black opacity-30 mt-4 uppercase tracking-[0.8em]">Verified Listing • Forever Home Search</p>
              </div>
          </div>
        </div>
      </div>
    </div>
  );
